/**
 * Get the list of supported trading pairs.
 * @returns {Array<{baseAsset: string, quoteAsset: string}>} Array of trading pairs
 */
export function getSupportedTradingPairs() {
	return [...supportedTradingPairs];
}

/**
 * Get the instrument catalog with all supported instruments.
 * @returns {Object} Map of asset IDs to instrument definitions
 */
export function getInstrumentCatalog() {
	return { ...instrumentCatalog };
}


function resolveContextKeyValue(...candidates) {
	for (const value of candidates) {
		if (typeof value === "string" && value.trim().length > 0) {
			return value.trim();
		}
	}
	return null;
}

function buildAmuletContextKeys(source = {}) {
	const amuletRules = resolveContextKeyValue(source.amuletRules, source.amulet_rules, DEFAULT_AMULET_CONTEXT_KEYS.amuletRules);
	const featuredAppRight = resolveContextKeyValue(source.featuredAppRight, source.featured_app_right, DEFAULT_AMULET_CONTEXT_KEYS.featuredAppRight);
	const openRound = resolveContextKeyValue(source.openRound, source.open_round, DEFAULT_AMULET_CONTEXT_KEYS.openRound);
	const expireLock = resolveContextKeyValue(source.expireLock, source.expire_lock, DEFAULT_AMULET_CONTEXT_KEYS.expireLock);

	return {
		amuletRules,
		amulet_rules: amuletRules,
		featuredAppRight,
		featured_app_right: featuredAppRight,
		openRound,
		open_round: openRound,
		expireLock,
		expire_lock: expireLock,
	};
}

function matchesDso(payload, dso) {
	if (!payload || !dso) {
		return false;
	}
	const target = dso.trim();
	if (!target) {
		return false;
	}
	const candidates = [payload.dso, payload.provider, payload.admin, payload.dsoParty, payload.rulesProvider, payload.dsoPartyId, payload.round?.dso, payload.round?.provider];
	return candidates.some((value) => typeof value === "string" && value.trim() === target);
}

const utilityInstrumentConfigurationCache = new Map();
const utilityAllocationFactoryCache = new Map();
const utilityCredentialCache = new Map();
let cachedInstrumentConfigurationContracts = null;
let cachedAllocationFactoryContracts = null;
let featuredAppRightLedgerCache = null;
// Cache for consolidated Amulet context from transfer-factory endpoint
let amuletTransferFactoryCache = null;
let amuletTransferFactoryCacheExpiry = 0;
const AMULET_TRANSFER_FACTORY_CACHE_TTL_MS = 5 * 60 * 1000; // 5 minutes

function extractInstrumentIdentifier(payload) {
	return payload?.defaultIdentifier || payload?.instrument || payload?.instrumentId || null;
}

function matchesInstrumentConfiguration(payload, utilityAsset, registrar) {
	const identifier = extractInstrumentIdentifier(payload) || {};
	const assetId = identifier.id || payload?.instrumentId?.id || payload?.instrument?.id;
	const source = identifier.source || payload?.registrar || payload?.provider;
	const assetMatches = utilityAsset ? assetId === utilityAsset : true;
	const registrarMatches = registrar ? source === registrar || payload?.registrar === registrar || payload?.provider === registrar : true;
	return assetMatches && registrarMatches;
}

function matchesAllocationFactory(payload, registrar) {
	if (!registrar) {
		return true;
	}
	return payload?.registrar === registrar || payload?.operator === registrar || payload?.provider === registrar;
}

function extractCredentialHolder(payload) {
	return payload?.holder || payload?.credential?.holder || payload?.owner || payload?.party;
}

async function loadUtilityInstrumentConfigurationsCache(forceReload = false) {
	if (cachedInstrumentConfigurationContracts && !forceReload) {
		return cachedInstrumentConfigurationContracts;
	}
	const response = await getUtilityInstrumentConfigurations();
	const contracts = unwrapActiveContracts(response).map(mapActiveContractMetadata).filter(Boolean);
	cachedInstrumentConfigurationContracts = contracts;
	return contracts;
}

async function loadUtilityAllocationFactoriesCache(forceReload = false) {
	if (cachedAllocationFactoryContracts && !forceReload) {
		return cachedAllocationFactoryContracts;
	}
	const response = await getUtilityAllocationFactory();
	const contracts = unwrapActiveContracts(response).map(mapActiveContractMetadata).filter(Boolean);
	cachedAllocationFactoryContracts = contracts;
	return contracts;
}

export async function resolveUtilityInstrumentConfiguration(utilityAsset, registrar) {
	const cacheKey = `${registrar || "*"}::${utilityAsset || "*"}`;
	if (utilityInstrumentConfigurationCache.has(cacheKey)) {
		return utilityInstrumentConfigurationCache.get(cacheKey);
	}
	const contracts = await loadUtilityInstrumentConfigurationsCache();

	const match =
		contracts.find((entry) => matchesInstrumentConfiguration(entry.payload, utilityAsset, registrar)) ||
		contracts.find((entry) => matchesInstrumentConfiguration(entry.payload, utilityAsset, null)) ||
		null;
	const metadata = toContractMetadata(match);
	utilityInstrumentConfigurationCache.set(cacheKey, metadata);
	return metadata;
}

export async function resolveUtilityAllocationFactory(registrar, holder = null) {
	const cacheKey = `${registrar || "*"}::${holder || "*"}`;
	if (utilityAllocationFactoryCache.has(cacheKey)) {
		return utilityAllocationFactoryCache.get(cacheKey);
	}
	const contracts = await loadUtilityAllocationFactoriesCache();

	// If holder is specified, try to find an exact match first
	let match = null;
	if (holder) {
		match = contracts.find((entry) => matchesAllocationFactory(entry.payload, registrar) && entry.payload?.holder === holder);
	}

	// Fall back to registrar-only match if no holder-specific match found
	if (!match) {
		match = contracts.find((entry) => matchesAllocationFactory(entry.payload, registrar)) || null;
	}

	if (!match) {
		console.error(`No allocation factory found for registrar ${registrar}.`);
		return null;
	}
	const metadata = toContractMetadata(match);
	utilityAllocationFactoryCache.set(cacheKey, metadata);
	return metadata;
}

/**
 * Create a utility credential for a holder on a given registrar.
 * @param {string} holder - The party ID of the credential holder
 * @param {string} registrar - The registrar party ID
 * @param {string} [credentialId="tSBC"] - The credential identifier
 * @param {boolean} [returnCommand=false] - If true, returns the raw command and endpoint instead of executing
 * @returns {Promise<Object|null>} The created credential data, or null on failure
 */
export async function createUtilityCredential(holder, registrar, credentialId = "tSBC", returnCommand = false) {
	if (!holder || !registrar) {
		console.error("Missing holder or registrar for createUtilityCredential");
		return null;
	}

	const schema = getSchema("createUtilityCredential");
	const templateVars = {
		"utility-app-credential-packageId": shouldUseLedgerForMetadata() ? "#utility-credential-v0" : config.PACKAGE_UTILITY_APP_CREDENTIAL_ID,
		registrar: registrar,
		holder: holder,
		credential_id: credentialId,
		temple: config.TEMPLE_PARTY_ID,
	};
	const command = replaceTemplateVariables(schema, templateVars);
	const endpoint = `${config.VALIDATOR_API_URL}/v2/commands/submit-and-wait`;

	if (returnCommand) {
		return { command, endpoint };
	}

	const headers = await buildHeaders();

	try {
		const response = await axios.post(endpoint, command, { headers });
		return response.data;
	} catch (error) {
		const errorData = error?.response?.data;
		const errorDetail = errorData ? JSON.stringify(errorData, null, 2) : error.message;
		console.error(`Error creating utility credential: ${errorDetail}`);
		return null;
	}
}

async function resolveUtilityCredentialForParty(party, registrar = null, autoCreate = true) {
	if (!party) {
		return null;
	}
	if (utilityCredentialCache.has(party)) {
		return utilityCredentialCache.get(party);
	}
	const response = await getUtilitySenderCredentials(party);
	const contracts = unwrapActiveContracts(response).map(mapActiveContractMetadata).filter(Boolean);
	let match = contracts.find((entry) => extractCredentialHolder(entry.payload) === party) || null;

	if (!match && autoCreate && registrar) {
		// Auto-create credential for this party
		// Auto-create credential for this party
		const createResult = await createUtilityCredential(party, registrar);
		if (createResult) {
			// Clear cache and re-fetch to get the newly created credential
			utilityCredentialCache.delete(party);
			const refreshedResponse = await getUtilitySenderCredentials(party);
			const refreshedContracts = unwrapActiveContracts(refreshedResponse).map(mapActiveContractMetadata).filter(Boolean);
			match = refreshedContracts.find((entry) => extractCredentialHolder(entry.payload) === party) || null;
		}
	}

	if (!match) {
		console.error(`No credential found for party ${party}.`);
		return null;
	}
	const metadata = toContractMetadata(match);
	utilityCredentialCache.set(party, metadata);
	return metadata;
}

async function resolveUtilityCip56Context({ party, registrar, utilityAsset }) {
	// Get the expected registrar from instrument definition - NO FALLBACKS for utility tokens
	const instrumentDef = resolveInstrumentDefinition(utilityAsset);
	const network = config.NETWORK;
	const requiresCredentials = instrumentDef?.requireCredentials !== false;
	// For utility tokens, the registrar MUST come from the instrument catalog
	const catalogRegistrar = instrumentDef?.[network].registrar || null;
	const expectedRegistrar = registrar || catalogRegistrar;

	if (!expectedRegistrar) {
		console.error(`No registrar defined for utility asset ${utilityAsset} in instrument catalog`);
		return null;
	}

	// Use the registrar from: 1. Passed in value, or 2. Instrument catalog - NO OTHER FALLBACKS
	const resolvedRegistrar = registrar || catalogRegistrar;

	// For testnet/mainnet, use hardcoded contracts from instrument catalog
	if (network !== NETWORK_LOCALHOST && instrumentDef) {
		// Get the network-specific contracts from the instrument catalog
		const networkContracts = instrumentDef[network]; // testnet or mainnet

		if (!networkContracts) {
			console.error(`No ${network} contracts defined for utility asset ${utilityAsset} in instrument catalog`);
			return null;
		}

		const {
			instrumentConfiguration: instConfig,
			allocationFactory: allocFactory,
			appRewardConfiguration: appRewardConfig,
			featuredAppRight: featuredAppRightConfig,
			synchronizerId: catalogSynchronizerId,
		} = networkContracts;

		if (!instConfig || !allocFactory) {
			console.error(`Missing instrumentConfiguration or allocationFactory for ${utilityAsset} on ${network}`);
			return null;
		}

		if (!appRewardConfig) {
			console.warn(`Missing appRewardConfiguration for ${utilityAsset} on ${network} - validators may not receive rewards`);
		}

		if (!featuredAppRightConfig) {
			console.warn(`Missing featuredAppRight for ${utilityAsset} on ${network} - validators may not receive rewards`);
		}

		// Extract package IDs from the catalog's templateIds to ensure consistency with event blobs
		const extractPackageIdFromTemplateId = (templateId) => {
			if (!templateId) return null;
			const parts = templateId.split(":");
			return parts.length >= 1 ? parts[0] : null;
		};

		const registryPackageId = extractPackageIdFromTemplateId(instConfig.templateId) || config.PACKAGE_UTILITY_APP_REGISTRY_ID;
		const registryAppPackageId = extractPackageIdFromTemplateId(allocFactory.templateId) || config.PACKAGE_UTILITY_APP_REGISTRY_APP_ID;

		const instrumentConfiguration = {
			contractCid: normalizeContractId(instConfig.contractId),
			disclosureCid: instConfig.eventBlob,
			synchronizerId: catalogSynchronizerId,
			templateId: instConfig.templateId,
		};

		const allocationFactory = {
			contractCid: normalizeContractId(allocFactory.contractId),
			disclosureCid: allocFactory.eventBlob,
			synchronizerId: catalogSynchronizerId,
			templateId: allocFactory.templateId,
		};

		// Build appRewardConfiguration if available
		const appRewardConfiguration = appRewardConfig
			? {
					contractCid: normalizeContractId(appRewardConfig.contractId),
					disclosureCid: appRewardConfig.eventBlob,
					synchronizerId: catalogSynchronizerId,
					templateId: appRewardConfig.templateId,
				}
			: null;

		// Build featuredAppRight from catalog (for USDCx, this is their FeaturedAppRight, not ours)
		const featuredAppRight = featuredAppRightConfig
			? {
					contractCid: normalizeContractId(featuredAppRightConfig.contractId),
					disclosureCid: featuredAppRightConfig.eventBlob || null,
					synchronizerId: catalogSynchronizerId,
					templateId: featuredAppRightConfig.templateId || null,
				}
			: null;

		// For testnet/mainnet, sender credentials need to be queried from ledger
		// since they are user-specific (the user's Credential contract)
		const senderCredentials = requiresCredentials ? await resolveUtilityCredentialForParty(party, expectedRegistrar) : null;

		// Build disclosed contracts array for the command
		const disclosedContracts = [
			{
				templateId: instConfig.templateId,
				contractId: instConfig.contractId,
				createdEventBlob: instConfig.eventBlob,
				synchronizerId: catalogSynchronizerId,
			},
			{
				templateId: allocFactory.templateId,
				contractId: allocFactory.contractId,
				createdEventBlob: allocFactory.eventBlob,
				synchronizerId: catalogSynchronizerId,
			},
		];

		// Add appRewardConfiguration to disclosures if available (required for validator rewards)
		if (appRewardConfig) {
			disclosedContracts.push({
				templateId: appRewardConfig.templateId,
				contractId: appRewardConfig.contractId,
				createdEventBlob: appRewardConfig.eventBlob,
				synchronizerId: catalogSynchronizerId,
			});
		}

		// Add FeaturedAppRight to disclosures if available (required for validator rewards)
		if (featuredAppRight) {
			disclosedContracts.push({
				templateId: featuredAppRight.templateId,
				contractId: featuredAppRight.contractCid,
				createdEventBlob: featuredAppRight.disclosureCid,
				synchronizerId: featuredAppRight.synchronizerId,
			});
		}

		return {
			registrar: resolvedRegistrar,
			packages: {
				registryApp: registryAppPackageId,
				registry: registryPackageId,
				credential: config.PACKAGE_UTILITY_APP_CREDENTIAL_ID,
			},
			contextKeys: {
				instrumentConfiguration: DEFAULT_UTILITY_CONTEXT_KEYS.instrumentConfiguration,
				senderCredentials: DEFAULT_UTILITY_CONTEXT_KEYS.senderCredentials,
			},
			instrumentConfiguration,
			allocationFactory,
			appRewardConfiguration,
			featuredAppRight,
			senderCredentials,
			requiresCredentials,
			disclosedContracts,
		};
	}

	// For localhost, use direct ledger queries
	// For order creation, we only need sender credentials (the user's credentials)
	// Receiver credentials are resolved at settlement time, not order creation
	// Pass party as holder to find the correct AllocationFactory for this holder
	const instrumentConfigurationPromise = resolveUtilityInstrumentConfiguration(utilityAsset, expectedRegistrar);
	const allocationFactoryPromise = resolveUtilityAllocationFactory(expectedRegistrar, party);
	const senderCredentialsPromise = requiresCredentials ? resolveUtilityCredentialForParty(party, expectedRegistrar) : Promise.resolve(null);

	const [instrumentConfiguration, allocationFactory, senderCredentials] = await Promise.all([instrumentConfigurationPromise, allocationFactoryPromise, senderCredentialsPromise]);

	return {
		registrar: resolvedRegistrar,
		packages: {
			registryApp: config.PACKAGE_UTILITY_APP_REGISTRY_APP_ID,
			registry: config.PACKAGE_UTILITY_APP_REGISTRY_ID,
			credential: config.PACKAGE_UTILITY_APP_CREDENTIAL_ID,
		},
		contextKeys: {
			instrumentConfiguration: DEFAULT_UTILITY_CONTEXT_KEYS.instrumentConfiguration,
			senderCredentials: DEFAULT_UTILITY_CONTEXT_KEYS.senderCredentials,
		},
		instrumentConfiguration,
		allocationFactory,
		senderCredentials,
		requiresCredentials,
	};
}

/**
 * Precisely sum decimal string amounts using BigInt to avoid floating point errors.
 * Canton uses Numeric 10 (up to 10 decimal places).
 * @param {string[]} amounts - Array of decimal string amounts (e.g., ["1.0000000000", "6.8100000000"])
 * @returns {string} Precise sum as a decimal string
 */
function sumDecimalStrings(amounts) {
	const PRECISION = 10;
	const MULTIPLIER = BigInt(10 ** PRECISION);
	let total = BigInt(0);
	for (const amt of amounts) {
		const str = String(amt || "0");
		const parts = str.split(".");
		const intPart = BigInt(parts[0] || "0");
		const fracStr = (parts[1] || "").padEnd(PRECISION, "0").slice(0, PRECISION);
		total += intPart * MULTIPLIER + BigInt(fracStr);
	}
	const intResult = total / MULTIPLIER;
	const fracResult = total % MULTIPLIER;
	return `${intResult}.${fracResult.toString().padStart(PRECISION, "0")}`;
}

function toScanStyleContract(entry) {
	if (!entry) {
		return null;
	}
	const contractId = normalizeContractId(entry.contractId || entry.contractCid);
	if (!contractId) {
		return null;
	}
	return {
		contract_id: contractId,
		created_event_blob: entry.createdEventBlob,
		payload: entry.payload || {},
		template_id: entry.templateId || undefined,
	};
}

function buildContractMetadata(contract, domainId) {
	if (!contract) {
		return null;
	}
	const contractCid = normalizeContractId(contract.contract_id || contract.contractId);
	if (!contractCid || !contract.created_event_blob) {
		return null;
	}
	return {
		contractCid,
		disclosureCid: contract.created_event_blob,
		synchronizerId: domainId || null,
		templateId: contract.template_id || null,
	};
}

function getFeaturedAppRightEnvMetadata() {
	if (config.CONTRACT_FEATURED_APP_ID && config.DISCLOSURE_FEATURED_APP && config.SYNCHRONIZER_FEATURED_APP) {
		return {
			contractCid: normalizeContractId(config.CONTRACT_FEATURED_APP_ID),
			disclosureCid: config.DISCLOSURE_FEATURED_APP,
			synchronizerId: config.SYNCHRONIZER_FEATURED_APP || null,
			templateId: config.TEMPLATE_ID_FEATURED_APP,
		};
	}
	return null;
}

async function resolveFeaturedAppRightMetadata() {
	// Skip ledger call when using wallet adapter without validator URL
	const hasLedgerAccess = config.VALIDATOR_API_URL && !getWalletAdapter();
	if (hasLedgerAccess && shouldUseLedgerForMetadata()) {
		if (featuredAppRightLedgerCache) {
			return featuredAppRightLedgerCache;
		}
		const ledgerResponse = await getFeaturedAppRight();
		const ledgerContract = ledgerResponse?.featured_app_right?.contract;
		if (ledgerContract) {
			const metadata = buildContractMetadata(ledgerContract, ledgerResponse.featured_app_right.domain_id);
			if (metadata) {
				featuredAppRightLedgerCache = metadata;
				return metadata;
			}
		}
	}

	const envMetadata = getFeaturedAppRightEnvMetadata();
	if (envMetadata) {
		return envMetadata;
	}

	console.error("Missing Featured App Right metadata. Provide environment overrides or ensure ledger access.");
	return null;
}

/**
 * Resolves all Amulet context from a single transfer-factory call.
 * This consolidates what was previously 3 separate API calls:
 * - getAmuletRules() -> /amulet-rules
 * - getCandidateMiningRoundContract() -> /open-and-issuing-mining-rounds
 * - resolveExternalAmuletRulesMetadata() -> /registry/transfer-instruction/v1/transfer-factory
 *
 * The transfer-factory endpoint returns disclosedContracts containing:
 * - AmuletRules
 * - OpenMiningRound
 * - ExternalPartyAmuletRules
 * Plus choiceContextData with context keys (open-round, amulet-rules)
 *
 * @param {Object} params
 * @param {string} params.investor - The investor party ID
 * @param {string[]} params.holdingIds - Array of holding contract IDs
 * @param {number} params.transferAmount - The transfer amount
 * @returns {Object|null} Consolidated Amulet context or null on failure
 */
export async function resolveAmuletContext({ investor, holdingIds = [], transferAmount = 0 }) {
	const dso = config.VALIDATOR_DSO_PARTY_ID;

	// For localhost, fall back to individual queries
	if (shouldUseLedgerForMetadata()) {
		return resolveAmuletContextFromLedger({ investor, holdingIds, transferAmount });
	}

	// Check cache (with TTL)
	const now = Date.now();
	if (amuletTransferFactoryCache && now < amuletTransferFactoryCacheExpiry) {
		return amuletTransferFactoryCache;
	}

	// Fetch from transfer-factory endpoint
	const normalizedHoldingIds = (holdingIds || []).map(normalizeContractId).filter((id) => typeof id === "string" && id.length > 0);

	let transferFactoryData;
	try {
		transferFactoryData = await getTransferFactory(investor, dso, transferAmount, normalizedHoldingIds);
	} catch (error) {
		console.error(`Failed to fetch transfer factory: ${error}`);
		return null;
	}

	if (!transferFactoryData?.choiceContext) {
		console.error("Transfer factory response missing choiceContext");
		return null;
	}

	const disclosed = transferFactoryData.choiceContext.disclosedContracts;
	if (!Array.isArray(disclosed) || disclosed.length === 0) {
		console.error("Transfer factory response has no disclosed contracts");
		return null;
	}

	// Extract AmuletRules
	const amuletRulesDisclosure = findDisclosedContract(disclosed, "Splice.AmuletRules:AmuletRules");
	if (!amuletRulesDisclosure) {
		console.error("AmuletRules not found in transfer factory disclosed contracts");
		return null;
	}

	// Extract OpenMiningRound
	const openMiningRoundDisclosure = findDisclosedContract(disclosed, "Splice.Round:OpenMiningRound");
	if (!openMiningRoundDisclosure) {
		console.error("OpenMiningRound not found in transfer factory disclosed contracts");
		return null;
	}

	// Extract ExternalPartyAmuletRules
	const externalAmuletRulesDisclosure = findDisclosedContract(disclosed, "Splice.ExternalPartyAmuletRules:ExternalPartyAmuletRules");
	if (!externalAmuletRulesDisclosure) {
		console.error("ExternalPartyAmuletRules not found in transfer factory disclosed contracts");
		return null;
	}

	// Extract context keys from choiceContextData
	const contextData = transferFactoryData.choiceContext.choiceContextData?.values || {};
	const amuletRulesContextKey = Object.keys(contextData).find((k) => k.includes("amulet-rules") || k.includes("amuletRules")) || DEFAULT_AMULET_CONTEXT_KEYS.amuletRules;
	const openRoundContextKey = Object.keys(contextData).find((k) => k.includes("open-round") || k.includes("openRound")) || DEFAULT_AMULET_CONTEXT_KEYS.openRound;

	// Get Featured App Right from env (hardcoded)
	const featuredAppRightMetadata = await resolveFeaturedAppRightMetadata();
	if (!featuredAppRightMetadata) {
		console.error("Unable to resolve Featured App Right metadata.");
		return null;
	}

	const result = {
		amuletRules: {
			contractCid: normalizeContractId(amuletRulesDisclosure.contractId),
			disclosureCid: amuletRulesDisclosure.createdEventBlob,
			synchronizerId: amuletRulesDisclosure.synchronizerId,
			templateId: amuletRulesDisclosure.templateId,
		},
		openMiningRound: {
			contractCid: normalizeContractId(openMiningRoundDisclosure.contractId),
			disclosureCid: openMiningRoundDisclosure.createdEventBlob,
			synchronizerId: openMiningRoundDisclosure.synchronizerId,
			templateId: openMiningRoundDisclosure.templateId,
		},
		externalAmuletRules: {
			contractCid: normalizeContractId(externalAmuletRulesDisclosure.contractId),
			disclosureCid: externalAmuletRulesDisclosure.createdEventBlob,
			synchronizerId: externalAmuletRulesDisclosure.synchronizerId,
			templateId: externalAmuletRulesDisclosure.templateId,
		},
		featuredAppRight: featuredAppRightMetadata,
		contextKeys: {
			amuletRules: amuletRulesContextKey,
			openRound: openRoundContextKey,
			featuredAppRight: DEFAULT_AMULET_CONTEXT_KEYS.featuredAppRight,
			expireLock: DEFAULT_AMULET_CONTEXT_KEYS.expireLock,
		},
		dso,
	};

	// Cache the result
	amuletTransferFactoryCache = result;
	amuletTransferFactoryCacheExpiry = now + AMULET_TRANSFER_FACTORY_CACHE_TTL_MS;

	return result;
}

/**
 * Fallback for localhost: resolve Amulet context from individual ledger queries
 */
async function resolveAmuletContextFromLedger({ investor, holdingIds, transferAmount }) {
	const dso = config.VALIDATOR_DSO_PARTY_ID;

	// Parallel fetch all required contracts
	const [amuletRulesData, miningRoundsData, externalAmuletRulesData, featuredAppRightMetadata] = await Promise.all([
		getAmuletRules(dso),
		getOpenMiningRounds(dso),
		getExternalAmuletRules(dso),
		resolveFeaturedAppRightMetadata(),
	]);

	if (!amuletRulesData?.amulet_rules?.contract) {
		console.error("Failed to get AmuletRules from ledger");
		return null;
	}

	if (!miningRoundsData?.open_mining_rounds?.length) {
		console.error("Failed to get OpenMiningRounds from ledger");
		return null;
	}

	if (!externalAmuletRulesData?.external_amulet_rules?.contract) {
		console.error("Failed to get ExternalPartyAmuletRules from ledger");
		return null;
	}

	if (!featuredAppRightMetadata) {
		console.error("Failed to get FeaturedAppRight metadata");
		return null;
	}

	const amuletRulesContract = amuletRulesData.amulet_rules.contract;
	const amuletRulesDomainId = amuletRulesData.amulet_rules.domain_id;

	// Find a currently open mining round
	const now = new Date();
	let selectedRound = null;
	for (const roundEntry of miningRoundsData.open_mining_rounds) {
		const round = roundEntry.contract;
		const opensAt = new Date(round.payload?.opensAt);
		const targetClosesAt = new Date(round.payload?.targetClosesAt);
		if (now >= opensAt && now <= targetClosesAt) {
			selectedRound = {
				contract: round,
				domain_id: roundEntry.domain_id,
			};
			break;
		}
	}

	if (!selectedRound) {
		console.error("No currently open mining round found");
		return null;
	}

	const externalRulesContract = externalAmuletRulesData.external_amulet_rules.contract;
	const externalRulesDomainId = externalAmuletRulesData.external_amulet_rules.domain_id;

	const contextKeys = amuletRulesData.context_keys || {};

	return {
		amuletRules: {
			contractCid: normalizeContractId(amuletRulesContract.contract_id),
			disclosureCid: amuletRulesContract.created_event_blob,
			synchronizerId: amuletRulesDomainId,
			templateId: amuletRulesContract.template_id,
		},
		openMiningRound: {
			contractCid: normalizeContractId(selectedRound.contract.contract_id),
			disclosureCid: selectedRound.contract.created_event_blob,
			synchronizerId: selectedRound.domain_id,
			templateId: selectedRound.contract.template_id,
		},
		externalAmuletRules: {
			contractCid: normalizeContractId(externalRulesContract.contract_id),
			disclosureCid: externalRulesContract.created_event_blob,
			synchronizerId: externalRulesDomainId,
			templateId: externalRulesContract.template_id,
		},
		featuredAppRight: featuredAppRightMetadata,
		contextKeys: {
			amuletRules: contextKeys.amuletRules || contextKeys.amulet_rules || DEFAULT_AMULET_CONTEXT_KEYS.amuletRules,
			openRound: contextKeys.openRound || contextKeys.open_round || DEFAULT_AMULET_CONTEXT_KEYS.openRound,
			featuredAppRight: contextKeys.featuredAppRight || contextKeys.featured_app_right || DEFAULT_AMULET_CONTEXT_KEYS.featuredAppRight,
			expireLock: contextKeys.expireLock || contextKeys.expire_lock || DEFAULT_AMULET_CONTEXT_KEYS.expireLock,
		},
		dso,
	};
}

// Schemas object for easy lookup
const schemas = {
	createOrderProposalAmulet: createOrderProposalAmuletSchema,
	createOrderProposalUtility: createOrderProposalUtilitySchema,
	getAmuletHoldings: getAmuletHoldingsSchema,
	getLockedAmuletHoldings: getLockedAmuletHoldingsSchema,
	getUtilityHoldings: getUtilityHoldingsSchema,
	getUtilityInstrumentConfigurations: getUtilityInstrumentConfigurationsSchema,
	getUtilityAllocationFactory: getUtilityAllocationFactorySchema,
	getUtilitySenderCredentials: getUtilitySenderCredentialsSchema,
	getOrderProposals: getOrderProposalsSchema,
	getOrders: getOrdersSchema,
	getTransferFactory: getTransferFactorySchema,
	executeTransferFactory: executeTransferFactorySchema,
	unlockAmulet: unlockAmuletSchema,
	createUtilityCredential: createUtilityCredentialSchema,
};

// Helper function to get a schema by name
function getSchema(schemaName) {
	// Return a copy of the schema to avoid mutations
	return JSON.parse(JSON.stringify(schemas[schemaName]));
}

// Helper function to replace template variables in a schema
function replaceTemplateVariables(schema, variables) {
	let schemaStr = JSON.stringify(schema);

	// Always replace the {{randomUUID}} placeholder
	variables.randomUUID = randomUUID();

	// Replace each variable in the format {{variableName}}
	for (const [key, value] of Object.entries(variables)) {
		// Escape special regex characters in the key (including hyphens)
		const escapedKey = key.replace(/[.*+?^${}()|[\]\\-]/g, "\\$&");

		// First, try to replace as a full value: "{{key}}" -> proper JSON value
		const fullValueRegex = new RegExp(`"\\{\\{${escapedKey}\\}\\}"`, "g");
		let jsonValue = JSON.stringify(value);
		schemaStr = schemaStr.replace(fullValueRegex, jsonValue);

		// Then, replace as part of a string: {{key}} -> string value (without outer quotes)
		const partialValueRegex = new RegExp(`\\{\\{${escapedKey}\\}\\}`, "g");
		// For string values, remove the outer quotes from JSON.stringify result
		const stringValue = typeof value === "string" ? value : String(value);
		schemaStr = schemaStr.replace(partialValueRegex, stringValue);
	}

	return JSON.parse(schemaStr);
}

/**
 * Determine if an order requires Amulet context based on the trading pair and side.
 * Amulet context is needed when selling Amulet (base) or buying with Amulet (quote).
 * @param {string} baseAsset - The base asset (e.g., "Amulet")
 * @param {string} quoteAsset - The quote asset (e.g., "USDCx")
 * @param {string} side - "Buy" or "Sell"
 * @returns {boolean|null} True if Amulet context is needed, false if not, null if invalid symbol
 */
export function checkAmuletContext(baseAsset, quoteAsset, side) {
	const symbolPair = supportedSymbols[`${baseAsset}/${quoteAsset}`];
	if (!symbolPair) {
		return null; // Invalid symbol
	}

	return (side === "Sell" && baseAsset === "Amulet") || (side === "Buy" && quoteAsset === "Amulet");
}

async function queryLedgerContractsByTemplate(templateId, returnCommand = false) {
	if (!templateId) {
		console.error("Template ID is required to query ledger contracts.");
		return null;
	}

	const ledgerEnd = await getLedgerEnd();
	if (ledgerEnd === null) {
		console.error(`Cannot retrieve ledger end. Aborting query for template ${templateId}.`);
		return null;
	}

	const command = {
		verbose: true,
		activeAtOffset: ledgerEnd,
		filter: {
			filtersByParty: {},
			filtersForAnyParty: {
				cumulative: [
					{
						identifierFilter: {
							TemplateFilter: {
								value: {
									templateId,
									includeCreatedEventBlob: true,
								},
							},
						},
					},
				],
			},
		},
	};

	const endpoint = `${config.VALIDATOR_API_URL}/v2/state/active-contracts`;
	if (returnCommand) {
		return { command, endpoint };
	}

	const headers = await buildHeaders();

	try {
		const response = await axios.post(endpoint, command, { headers });
		return unwrapActiveContracts(response.data).map(mapActiveContractMetadata).filter(Boolean);
	} catch (error) {
		console.error(`Error fetching contracts for template ${templateId}: ${error}`);
		return null;
	}
}

/**
 * Get the AmuletRules contract from the Scan API or local ledger.
 * @param {string} dso - The DSO party ID
 * @param {boolean} [returnCommand=false] - If true, returns the raw command/endpoint instead of executing
 * @returns {Promise<Object|null>} The AmuletRules contract data, or null on failure
 */
export async function getAmuletRules(dso, returnCommand = false) {
	if (!shouldUseLedgerForMetadata()) {
		const headers = await buildHeaders();
		const url = `${config.VALIDATOR_SCAN_API_URL}/amulet-rules?provider=${dso}`;
		if (returnCommand) {
			return { command: null, endpoint: url, method: "GET" };
		}
		try {
			const response = await axios.get(url, { headers });
			return response.data;
		} catch (error) {
			console.error(`Error fetching Amulet Transfer Rules: ${error}`);
			return null;
		}
	}

	const templateId = "#splice-amulet:Splice.AmuletRules:AmuletRules";
	if (returnCommand) {
		return queryLedgerContractsByTemplate(templateId, true);
	}

	const contracts = await queryLedgerContractsByTemplate(templateId);
	if (!Array.isArray(contracts) || contracts.length === 0) {
		console.error("No Amulet Rules contracts found on the ledger. Ensure the local sandbox has been bootstrapped.");
		return null;
	}

	const selected = contracts.find((entry) => matchesDso(entry.payload, dso)) || contracts[0];
	const contract = toScanStyleContract(selected);
	if (!contract) {
		console.error("Unable to format Amulet Rules contract from ledger response.");
		return null;
	}

	const contextKeys = buildAmuletContextKeys(selected.payload?.contextKeys || selected.payload?.context_keys || {});

	return {
		amulet_rules: {
			contract,
			domain_id: selected.synchronizerId,
		},
		context_keys: contextKeys,
	};
}

