/**
 * Get open and issuing mining rounds from the Scan API or local ledger.
 * @param {string} dso - The DSO party ID
 * @param {boolean} [returnCommand=false] - If true, returns the raw command/endpoint instead of executing
 * @returns {Promise<Object|null>} Mining rounds data with open_mining_rounds array, or null on failure
 */
export async function getOpenMiningRounds(dso, returnCommand = false) {
	if (!shouldUseLedgerForMetadata()) {
		const headers = await buildHeaders();
		const url = `${config.VALIDATOR_SCAN_API_URL}/open-and-issuing-mining-rounds?provider=${dso}`;
		if (returnCommand) {
			return { command: null, endpoint: url, method: "GET" };
		}
		try {
			const response = await axios.get(url, { headers });
			return response.data;
		} catch (error) {
			console.error(`Error fetching open mining rounds: ${error}`);
			return null;
		}
	}

	const templateId = "#splice-amulet:Splice.Round:OpenMiningRound";
	if (returnCommand) {
		return queryLedgerContractsByTemplate(templateId, true);
	}
	const contracts = await queryLedgerContractsByTemplate(templateId);
	if (!Array.isArray(contracts) || contracts.length === 0) {
		console.error("No Open Mining Round contracts found on the ledger. Ensure the local sandbox has been bootstrapped.");
		return null;
	}

	const filtered = dso ? contracts.filter((entry) => matchesDso(entry.payload, dso)) : contracts;
	const source = filtered.length > 0 ? filtered : contracts;
	const sorted = source.slice().sort((a, b) => {
		const aTime = new Date(a.payload?.opensAt || a.payload?.openAt || 0).getTime();
		const bTime = new Date(b.payload?.opensAt || b.payload?.openAt || 0).getTime();
		return bTime - aTime;
	});
	const openRounds = sorted
		.map((entry) => ({
			contract: toScanStyleContract(entry),
			domain_id: entry.synchronizerId,
		}))
		.filter((entry) => entry.contract !== null);

	return {
		open_mining_rounds: openRounds,
		issuing_mining_rounds: [],
	};
}

// Build transfer factory data for AMULET from local ledger (for localhost when Scan API is unavailable)
async function buildLocalAmuletTransferFactory(investor, dso, amount, holdingIds) {
	// Get ExternalPartyAmuletRules - this is the factory contract for Amulet
	const externalRulesData = await getExternalAmuletRules(dso);
	if (!externalRulesData || !externalRulesData.external_amulet_rules) {
		console.error("Failed to get ExternalPartyAmuletRules from local ledger");
		return null;
	}
	const externalRules = externalRulesData.external_amulet_rules;
	const factoryContractId = normalizeContractId(externalRules.contract.contract_id);

	// Get AmuletRules
	const amuletRulesData = await getAmuletRules(dso);
	if (!amuletRulesData || !amuletRulesData.amulet_rules) {
		console.error("Failed to get AmuletRules from local ledger");
		return null;
	}
	const amuletRules = amuletRulesData.amulet_rules;
	const amuletRulesContractId = normalizeContractId(amuletRules.contract.contract_id);

	// Get OpenMiningRound
	const miningRound = await getCandidateMiningRoundContract(dso);
	if (!miningRound) {
		console.error("Failed to get OpenMiningRound from local ledger");
		return null;
	}
	const openRoundContractId = normalizeContractId(miningRound.contractId);

	// Build the choiceContextData structure
	const choiceContextData = {
		values: {
			"open-round": {
				tag: "AV_ContractId",
				value: openRoundContractId,
			},
			"amulet-rules": {
				tag: "AV_ContractId",
				value: amuletRulesContractId,
			},
		},
	};

	// Build disclosed contracts array - use template_id from the actual contracts when available
	const disclosedContracts = [
		{
			templateId: externalRules.contract.template_id || "#splice-amulet:Splice.ExternalPartyAmuletRules:ExternalPartyAmuletRules",
			contractId: factoryContractId,
			createdEventBlob: externalRules.contract.created_event_blob,
			synchronizerId: externalRules.domain_id,
		},
		{
			templateId: amuletRules.contract.template_id || "#splice-amulet:Splice.AmuletRules:AmuletRules",
			contractId: amuletRulesContractId,
			createdEventBlob: amuletRules.contract.created_event_blob,
			synchronizerId: amuletRules.domain_id,
		},
		{
			templateId: miningRound.templateId || "#splice-amulet:Splice.Round:OpenMiningRound",
			contractId: openRoundContractId,
			createdEventBlob: miningRound.createdEventBlob,
			synchronizerId: miningRound.synchronizerId,
		},
	];

	return {
		factoryId: factoryContractId,
		choiceContext: {
			choiceContextData: choiceContextData,
			disclosedContracts: disclosedContracts,
		},
		transfer: {
			amount: amount,
			instrumentId: {
				admin: dso,
				id: "Amulet",
			},
		},
		expectedAdmin: dso,
	};
}

// Build transfer factory data for UTILITY TOKENS from local ledger
async function buildLocalUtilityTransferFactory(investor, registrar, amount, holdingIds, utilityAsset) {
	// Get the full utility context - includes AllocationFactory, InstrumentConfiguration, and Credentials
	const utilityContext = await resolveUtilityCip56Context({
		party: investor,
		registrar: registrar,
		utilityAsset: utilityAsset,
	});

	if (!utilityContext) {
		console.error(`Failed to get utility context for registrar ${registrar} from local ledger`);
		return null;
	}

	const { allocationFactory, instrumentConfiguration, senderCredentials, packages, contextKeys, requiresCredentials } = utilityContext;

	if (!allocationFactory?.contractCid) {
		console.error(`Failed to get AllocationFactory for registrar ${registrar} from local ledger`);
		return null;
	}

	const factoryContractId = normalizeContractId(allocationFactory.contractCid);

	// Build the choiceContextData structure for utility tokens
	// Utility tokens always need instrument-configuration in the context and
	// only include sender-credentials when the registrar requires them
	const choiceContextData = {
		values: {},
	};

	// Add instrument configuration to context if available
	if (instrumentConfiguration?.contractCid && contextKeys?.instrumentConfiguration) {
		choiceContextData.values[contextKeys.instrumentConfiguration] = {
			tag: "AV_ContractId",
			value: normalizeContractId(instrumentConfiguration.contractCid),
		};
	}

	// Add sender credentials to context when required and available
	// Note: sender-credentials must be a LIST of contract IDs
	if (requiresCredentials && senderCredentials?.contractCid && contextKeys?.senderCredentials) {
		choiceContextData.values[contextKeys.senderCredentials] = {
			tag: "AV_List",
			value: [
				{
					tag: "AV_ContractId",
					value: normalizeContractId(senderCredentials.contractCid),
				},
			],
		};
	}

	// Build disclosed contracts array - include all required contracts
	const disclosedContracts = [];

	// AllocationFactory (required)
	if (allocationFactory?.contractCid && allocationFactory?.disclosureCid) {
		disclosedContracts.push({
			templateId: `${packages?.registryApp || config.PACKAGE_UTILITY_APP_REGISTRY_APP_ID}:Utility.Registry.App.V0.Service.AllocationFactory:AllocationFactory`,
			contractId: factoryContractId,
			createdEventBlob: allocationFactory.disclosureCid,
			synchronizerId: allocationFactory.synchronizerId,
		});
	}

	// InstrumentConfiguration (required for transfers)
	if (instrumentConfiguration?.contractCid && instrumentConfiguration?.disclosureCid) {
		disclosedContracts.push({
			templateId: `${packages?.registry || config.PACKAGE_UTILITY_APP_REGISTRY_ID}:Utility.Registry.V0.Configuration.Instrument:InstrumentConfiguration`,
			contractId: normalizeContractId(instrumentConfiguration.contractCid),
			createdEventBlob: instrumentConfiguration.disclosureCid,
			synchronizerId: instrumentConfiguration.synchronizerId,
		});
	}

	// SenderCredentials (only when required)
	if (requiresCredentials && senderCredentials?.contractCid && senderCredentials?.disclosureCid) {
		disclosedContracts.push({
			templateId: `${packages?.credential || config.PACKAGE_UTILITY_APP_CREDENTIAL_ID}:Utility.Credential.V0.Credential:Credential`,
			contractId: normalizeContractId(senderCredentials.contractCid),
			createdEventBlob: senderCredentials.disclosureCid,
			synchronizerId: senderCredentials.synchronizerId,
		});
	}

	return {
		factoryId: factoryContractId,
		choiceContext: {
			choiceContextData: choiceContextData,
			disclosedContracts: disclosedContracts,
		},
		transfer: {
			amount: amount,
			instrumentId: {
				admin: registrar,
				id: utilityAsset || "tSBC",
			},
		},
		expectedAdmin: registrar,
	};
}

// Build transfer factory data from local ledger (for localhost when Scan API is unavailable)
// Determines whether to use Amulet or Utility token path based on the admin party
async function buildLocalTransferFactory(investor, admin, amount, holdingIds, utilityAsset = null) {
	// Determine if this is an Amulet (DSO) or utility token (Registrar) operation
	const isAmulet = admin && admin.includes("DSO");

	if (isAmulet) {
		return buildLocalAmuletTransferFactory(investor, admin, amount, holdingIds);
	} else {
		return buildLocalUtilityTransferFactory(investor, admin, amount, holdingIds, utilityAsset);
	}
}

// Get transfer factory from the public registry API (no auth required).
// Used by wallet provider flows where Scan API is not available.
async function getTransferFactoryFromRegistry(investor, registrar, amount, holdingIds, utilityAsset) {
	const instrumentDef = resolveInstrumentDefinition(utilityAsset);
	const networkContracts = instrumentDef?.[config.NETWORK];
	const registryAPI = networkContracts?.registryAPI;
	if (!registryAPI) {
		console.error(`No registryAPI defined for ${utilityAsset} on ${config.NETWORK}`);
		return null;
	}
	const url = `${registryAPI}/transfer-instruction/v1/transfer-factory`;
	const schema = getSchema("getTransferFactory");
	const templateVars = {
		investor: investor,
		dso: registrar,
		amount: amount,
		holding_ids: holdingIds,
		instrument_id: utilityAsset,
		time: new Date().toISOString(),
		timeEnd: new Date(Date.now() + 3600 * 1000).toISOString(),
	};
	const body = replaceTemplateVariables(schema, templateVars);
	try {
		const response = await axios.post(url, body);
		return response.data;
	} catch (error) {
		console.error(`Error fetching transfer factory from registry API: ${error}`);
		if (error.response) {
			console.error(`Response data: ${JSON.stringify(error.response.data)}`);
		}
		return null;
	}
}

/**
 * Get a transfer factory from the Scan API, or build one locally for localhost environments.
 * @param {string} investor - The investor party ID
 * @param {string} admin - The admin party ID (DSO for Amulet, registrar for utility tokens)
 * @param {number|string} amount - The transfer amount
 * @param {string[]} holdingIds - Array of holding contract IDs
 * @param {boolean} [returnCommand=false] - If true, returns the raw command/endpoint instead of executing
 * @param {string|null} [utilityAsset=null] - The utility asset ID (e.g., "USDCx") for localhost utility transfers
 * @returns {Promise<Object|null>} Transfer factory data, or null on failure
 */
export async function getTransferFactory(investor, admin, amount, holdingIds, returnCommand = false, utilityAsset = null) {
	// For localhost, build the transfer factory data from local ledger contracts
	if (shouldUseLedgerForMetadata()) {
		if (returnCommand) {
			// Return a placeholder indicating this will be built at runtime
			return { command: null, endpoint: "localhost-ledger", method: "LOCAL" };
		}
		return buildLocalTransferFactory(investor, admin, amount, holdingIds, utilityAsset);
	}

	const headers = await buildHeaders();
	const url = `${config.VALIDATOR_SCAN_API_URL}/registry/transfer-instruction/v1/transfer-factory`;
	const schema = getSchema("getTransferFactory");
	const templateVars = {
		investor: investor,
		dso: admin,
		amount: amount,
		holding_ids: holdingIds,
		instrument_id: utilityAsset || "Amulet",
		time: new Date().toISOString(),
		timeEnd: new Date(Date.now() + 3600 * 1000).toISOString(),
	};
	const command = replaceTemplateVariables(schema, templateVars);

	if (returnCommand) {
		return { command, endpoint: url };
	}

	try {
		const response = await axios.post(url, command, { headers });
		return response.data;
	} catch (error) {
		console.error(`Error fetching transfer factory: ${error}`);
		return null;
	}
}

/**
 * Get Amulet disclosure contracts (AmuletRules, ExternalPartyAmuletRules, OpenMiningRound) from the Scan API.
 * Used by external wallet integrations that cannot access the Scan API directly.
 * Not available for localhost environments.
 * @param {string} party - The party ID to fetch disclosures for
 * @returns {Promise<Array|null>} Array of disclosed contract objects, or null on failure
 */
export async function getAmuletDisclosures(party) {
	// For localhost, this endpoint is not available
	if (shouldUseLedgerForMetadata()) {
		console.error("getAmuletDisclosures is not available for localhost - use ledger-based resolution instead");
		return null;
	}

	const headers = await buildHeaders();
	const url = `${config.VALIDATOR_SCAN_API_URL}/registry/transfer-instruction/v1/transfer-factory`;
	const dso = config.VALIDATOR_DSO_PARTY_ID;

	// Use amount=0 and empty holding IDs to just get the disclosures without creating a real transfer
	const now = new Date();
	const tomorrow = new Date(now.getTime() + 24 * 60 * 60 * 1000);

	const requestBody = {
		choiceArguments: {
			expectedAdmin: dso,
			transfer: {
				sender: party,
				receiver: party,
				amount: "0",
				instrumentId: {
					admin: dso,
					id: "Amulet",
				},
				requestedAt: now.toISOString(),
				executeBefore: tomorrow.toISOString(),
				inputHoldingCids: [],
				meta: { values: {} },
			},
			extraArgs: {
				context: { values: {} },
				meta: { values: {} },
			},
		},
		excludeDebugFields: true,
	};

	try {
		const response = await axios.post(url, requestBody, { headers });

		// Return the disclosed contracts array
		if (response.data && response.data?.choiceContext?.disclosedContracts) {
			return response.data.choiceContext.disclosedContracts;
		}

		console.error("No disclosedContracts found in transfer-factory response");
		return null;
	} catch (error) {
		console.error(`Error fetching amulet disclosures: ${error}`);
		if (error.response) {
			console.error(`Response data: ${JSON.stringify(error.response.data)}`);
		}
		return null;
	}
}

/**
 * Get a currently-open mining round contract suitable for use in transactions.
 * @param {string} dso - The DSO party ID
 * @param {boolean} [returnCommand=false] - If true, returns the raw command/endpoint instead of executing
 * @returns {Promise<Object|null>} Mining round metadata (contractId, createdEventBlob, synchronizerId), or null if none found
 */
export async function getCandidateMiningRoundContract(dso, returnCommand = false) {
	const miningRoundsData = await getOpenMiningRounds(dso);
	if (!miningRoundsData || !miningRoundsData.open_mining_rounds || miningRoundsData.open_mining_rounds.length === 0) {
		console.error(`No open mining rounds found for DSO ${dso}`);
		return null;
	}

	const now = new Date();

	// Find a mining round that is currently open
	for (const roundEntry of miningRoundsData.open_mining_rounds) {
		const round = roundEntry.contract;
		const opensAt = new Date(round.payload.opensAt);
		const targetClosesAt = new Date(round.payload.targetClosesAt);

		if (now >= opensAt && now <= targetClosesAt) {
			return {
				contractId: round.contract_id,
				createdEventBlob: round.created_event_blob,
				synchronizerId: roundEntry.domain_id,
				templateId: round.template_id || null,
			};
		}
	}

	console.error(`No currently open mining round found for DSO ${dso}`);
	return null;
}

