/**
 * Get UTXO summary for a given asset and party.
 * Useful for confirming a merge was successful and checking if a holding is large enough for an order.
 * @param {string} party - The party ID
 * @param {string} assetId - The asset ID (e.g., "USDCx", "CBTC", "Amulet")
 * @param {Object|null} [provider=null] - Optional wallet provider
 * @returns {Promise<{total: number, unlocked: number, locked: number, largestUnlocked: number, unlockedBalance: number}>} UTXO summary
 */
export async function getUtxoCount(party, assetId, provider = null) {
	provider = resolveProvider(provider);
	const isAmulet = assetId === "Amulet";
	const holdings = isAmulet ? await getAmuletHoldingsForParty(party, false, provider) : await getUtilityHoldingsForParty(party, false, provider);

	if (!holdings || holdings.length === 0) {
		return { total: 0, unlocked: 0, locked: 0, largestUnlocked: 0, unlockedBalance: 0 };
	}

	let unlocked = 0;
	let locked = 0;
	let largestUnlocked = 0;
	let unlockedBalance = 0;

	for (const h of holdings) {
		const createdEvent = h.contractEntry?.JsActiveContract?.createdEvent;
		if (!createdEvent) continue;
		const createArg = createdEvent.createArgument;

		let isLocked = false;
		let quantity = 0;
		let matchesAsset = false;

		if (isAmulet) {
			isLocked = !!(createArg?.lock || createArg?.amulet?.lock);
			quantity = parseFloat(createArg?.amount?.initialAmount || 0);
			matchesAsset = true;
		} else {
			const asset = createArg?.instrument?.id || null;
			if (asset !== assetId) continue;
			isLocked = !!createArg?.lock;
			quantity = parseFloat(createArg?.amount || 0);
			matchesAsset = true;
		}

		if (!matchesAsset) continue;

		if (isLocked) {
			locked++;
		} else {
			unlocked++;
			unlockedBalance += quantity;
			if (quantity > largestUnlocked) {
				largestUnlocked = quantity;
			}
		}
	}

	return { total: unlocked + locked, unlocked, locked, largestUnlocked, unlockedBalance };
}

