/**
 * Find a suitable holding contract for order creation that meets the required quantity.
 * Searches Amulet or utility holdings and validates operator/provider/registrar compatibility.
 * @param {string} party - The party ID
 * @param {boolean} isAmulet - True to search Amulet holdings, false for utility holdings
 * @param {number|string} requiredQuantity - The minimum quantity required
 * @param {string|null} [expectedAssetId=null] - Expected asset ID for utility holdings (e.g., "USDCx")
 * @param {boolean} [returnCommand=false] - If true, returns the raw command/endpoint instead of executing
 * @param {Object|null} [provider=null] - Optional external provider to use instead of ledger API
 * @returns {Promise<Object>} Holding data with contractId, quantity, dso/registrar, or an error object
 */
export async function getCandidateHoldingForOrderCreation(party, isAmulet, requiredQuantity, expectedAssetId = null, returnCommand = false, provider = null) {
	provider = resolveProvider(provider);
	const holdings = isAmulet ? await getAmuletHoldingsForParty(party, false, provider) : await getUtilityHoldingsForParty(party, false, provider);

	if (!holdings || holdings.length === 0) {
		console.error(`No holdings found for party ${party}`);
		return {
			error: `No holdings found for party ${party}`,
		};
	}

	const network = config.NETWORK;

	// For utility holdings, resolve the expected values from the instrument definition
	let expectedRegistrar = null;
	let expectedInstrumentScheme = null;
	let expectedOperator = null;
	let expectedProvider = null;
	if (!isAmulet && expectedAssetId) {
		const instrumentDef = resolveInstrumentDefinition(expectedAssetId);
		if (instrumentDef) {
			expectedRegistrar = instrumentDef[network].registrar || null;
			expectedInstrumentScheme = instrumentDef[network].scheme || RegistrarInternalScheme;
			expectedOperator = instrumentDef[network].operator || null;
			expectedProvider = instrumentDef[network].provider || null;
		}
	}

	// Extract the actual contract data and map to a simpler structure
	const contracts = holdings
		.map((h) => {
			const createdEvent = h.contractEntry?.JsActiveContract?.createdEvent;
			if (!createdEvent) return null;
			const synchronizerId = h.contractEntry?.JsActiveContract?.synchronizerId;

			// For Amulet, DSO is in createArgument.dso
			// For Utility, registrar is in createArgument.instrument.source (which is the registrar)
			const holdingRegistrar = isAmulet ? null : createdEvent.createArgument?.registrar || createdEvent.createArgument?.instrument?.source || null;
			const dso = isAmulet ? createdEvent.createArgument?.dso || null : holdingRegistrar;

			// For Amulet, quantity is in amount.initialAmount
			// For Utility, quantity is in createArgument.amount
			const quantity = isAmulet ? parseFloat(createdEvent.createArgument?.amount?.initialAmount || 0) : parseFloat(createdEvent.createArgument?.amount || 0);

			// For Utility, also get the asset ID and scheme
			const asset = isAmulet ? "Amulet" : createdEvent.createArgument?.instrument?.id || null;
			const instrumentScheme = isAmulet ? null : createdEvent.createArgument?.instrument?.scheme || null;

			// Extract owner/holder/operator/provider for debugging
			const owner = createdEvent.createArgument?.owner || null;
			const holder = createdEvent.createArgument?.holder || null;
			const operator = createdEvent.createArgument?.operator || null;
			const provider = createdEvent.createArgument?.provider || null;

			// For Utility check the lock status and skip locked holdings. Amulets are never locked here.
			if (!isAmulet && createdEvent.createArgument?.lock) {
				return null;
			}

			return {
				contractId: normalizeContractId(createdEvent.contractId),
				quantity: quantity,
				createdEventBlob: createdEvent.createdEventBlob,
				synchronizerId: synchronizerId,
				dso: dso,
				registrar: holdingRegistrar,
				asset: asset,
				instrumentScheme: instrumentScheme,
				owner: owner,
				holder: holder,
				operator: operator,
				provider: provider,
			};
		})
		.filter((c) => c !== null);

	if (contracts.length === 0) {
		console.error(`No valid holdings found for party ${party}`);
		return {
			error: `No valid holdings found for party ${party}`,
		};
	}

	// For utility tokens, filter by expected registrar and asset if provided
	let eligibleContracts = contracts;
	if (!isAmulet) {
		eligibleContracts = contracts.filter((holding) => {
			// Filter by owner - the holding MUST belong to the party creating the order
			if (holding.owner && holding.owner !== party) {
				return false;
			}
			// Filter by expected asset if provided
			if (expectedAssetId && holding.asset) {
				if (holding.asset.toLowerCase() !== expectedAssetId.toLowerCase()) {
					return false;
				}
			}
			// Filter by expected registrar - MUST match for utility tokens
			if (expectedRegistrar && holding.registrar) {
				if (holding.registrar.toLowerCase() !== expectedRegistrar.toLowerCase()) {
					return false;
				}
			}
			// Filter by operator/provider - holdings must match the AllocationFactory's operator/provider
			// These values come from the instrument catalog to ensure compatibility
			if (expectedOperator && holding.operator && holding.operator !== expectedOperator) {
				return false;
			}
			if (expectedProvider && holding.provider && holding.provider !== expectedProvider) {
				return false;
			}
			return true;
		});

		if (eligibleContracts.length === 0) {
			console.error(
				`No holdings found for party ${party} matching owner=${party}, asset=${expectedAssetId}, registrar=${expectedRegistrar}, operator=${expectedOperator}, provider=${expectedProvider}`,
			);
			console.error(`Holdings available but filtered out may have incompatible operator/provider`);
			// Do NOT fall back - mismatch will cause transaction failure
			return {
				error: `No holdings found for party ${party} matching owner=${party}, asset=${expectedAssetId}, registrar=${expectedRegistrar}, operator=${expectedOperator}, provider=${expectedProvider}`,
			};
		}
	}

	// Sort by quantity ascending
	const sortedHoldings = eligibleContracts.sort((a, b) => a.quantity - b.quantity);

	// Check if any holding has sufficient quantity
	let totalBalance = 0;

	for (const holding of sortedHoldings) {
		totalBalance += holding.quantity;

		if (holding.quantity >= requiredQuantity) {
			// For Amulets, check DSO matches
			// For Utility tokens, DSO check is not applicable (source is different)
			if (isAmulet) {
				if (holding.dso === config.VALIDATOR_DSO_PARTY_ID) {
					return holding;
				} else {
					console.warn(`Holding ${holding.contractId} has sufficient quantity but DSO ${holding.dso} does not match required DSO ${config.VALIDATOR_DSO_PARTY_ID}`);
				}
			} else {
				return holding;
			}
		}
	}

	// No single holding has sufficient quantity
	console.error(`No single holding found for party ${party} with required quantity ${requiredQuantity}. Total balance available: ${totalBalance}`);
	console.error(`User has enough total balance but needs to merge his holdings`);

	return {
		error: `User has enough total balance but needs to merge his holdings`,
		data: {
			totalBalance: totalBalance,
			requiredQuantity: requiredQuantity,
		},
	};
}

/**
 * Merge Amulet holdings for a party into a single holding via a transfer factory.
 * Requires at least 2 holdings to merge. When using a provider (wallet integration),
 * returns the command for the wallet to sign instead of submitting directly.
 * @param {string} party - The party ID
 * @param {boolean} [returnCommand=false] - If true, returns the raw command/endpoint instead of executing
 * @param {Object|null} [provider=null] - Optional external provider (e.g., Loop Wallet) to use instead of ledger API
 * @param {number|null} [maxUtxos=null] - Maximum number of UTXOs to merge (picks smallest first). Null = merge all.
 * @param {Array} [amuletDisclosures=[]] - Pre-fetched Amulet disclosures (required when using a provider). Must contain AmuletRules, OpenMiningRound, and ExternalPartyAmuletRules.
 * @returns {Promise<Object|null>} Merge result data, or null on failure
 */
export async function mergeAmuletHoldingsForParty(party, returnCommand = false, provider = null, maxUtxos = null, amuletDisclosures = []) {
	provider = resolveProvider(provider);
	if (provider) {
		if (!amuletDisclosures || amuletDisclosures.length === 0) {
			console.error("amuletDisclosures are required when using a provider for Amulet merge");
			return { error: "amuletDisclosures are required when using a provider for Amulet merge" };
		}
		returnCommand = true;
		// Wallet providers (e.g., Loop) have a ~100 contract limit per transaction.
		if (!maxUtxos) {
			maxUtxos = 100;
		}
	}

	if (!provider) {
		const ledgerEnd = await getLedgerEnd();
		if (ledgerEnd === null) {
			console.error("Cannot retrieve ledger end. Aborting mergeAmuletHoldingsForParty.");
			return null;
		}
	}

	// To merge amulets we need to transfer them to the same party with a combined output of the total amount

	const holdings = await getAmuletHoldingsForParty(party, false, provider);
	if (!holdings || holdings.length < 2) {
		console.error(`Not enough holdings to merge for party ${party}`);
		return null;
	}

	// Extract the actual contract data and map to a simpler structure
	const contracts = holdings
		.map((h) => {
			const createdEvent = h.contractEntry?.JsActiveContract?.createdEvent;
			if (!createdEvent) return null;
			const synchronizerId = h.contractEntry?.JsActiveContract?.synchronizerId;
			const dso = createdEvent.createArgument?.dso || createdEvent.createArgument?.amulet?.dso || null;
			const rawAmount = createdEvent.createArgument?.amount?.initialAmount || createdEvent.createArgument?.amulet?.amount?.initialAmount || "0";
			const quantity = parseFloat(rawAmount);

			const contractId = normalizeContractId(createdEvent.contractId);

			return {
				contractId,
				quantity: quantity,
				rawAmount: rawAmount,
				createdEventBlob: createdEvent.createdEventBlob,
				synchronizerId: synchronizerId,
				dso: dso,
			};
		})
		.filter((c) => c !== null);

	if (contracts.length < 2) {
		console.error(`Not enough valid holdings to merge for party ${party}`);
		return null;
	}

	// Sort by quantity ascending (smallest first) and apply maxUtxos limit
	contracts.sort((a, b) => a.quantity - b.quantity);
	const selectedContracts = maxUtxos && maxUtxos < contracts.length ? contracts.slice(0, maxUtxos) : contracts;

	if (selectedContracts.length < 2) {
		console.error(`Not enough holdings after applying maxUtxos limit for party ${party}`);
		return null;
	}

	// Calculate total quantity using precise decimal math (BigInt) to avoid floating point drift
	const totalQuantity = sumDecimalStrings(selectedContracts.map((c) => c.rawAmount));

	// For simplicity, use the first holding's DSO and synchronizer
	const primaryHolding = selectedContracts[0];
	if (!primaryHolding.dso) {
		console.error(`Primary holding ${primaryHolding.contractId} does not have a DSO associated.`);
		return null;
	}

	// Get the transfer factory for the merge
	const holdingIds = selectedContracts.map((c) => c.contractId);
	const normalizedHoldingIds = normalizeContractReferences(holdingIds);

	let transferFactoryData;
	if (provider) {
		// Build transfer factory from pre-fetched amuletDisclosures
		const findDisclosure = (suffix) => amuletDisclosures.find((d) => d.templateId?.includes(suffix) || d.template_id?.includes(suffix));
		const amuletRulesDisclosure = findDisclosure("Splice.AmuletRules:AmuletRules");
		const openMiningRoundDisclosure = findDisclosure("Splice.Round:OpenMiningRound");
		const externalAmuletRulesDisclosure = findDisclosure("Splice.ExternalPartyAmuletRules:ExternalPartyAmuletRules");

		if (!amuletRulesDisclosure || !openMiningRoundDisclosure || !externalAmuletRulesDisclosure) {
			console.error("Missing required disclosures in amuletDisclosures array. Need AmuletRules, OpenMiningRound, and ExternalPartyAmuletRules.");
			return { error: "Missing required disclosures in amuletDisclosures array. Need AmuletRules, OpenMiningRound, and ExternalPartyAmuletRules." };
		}

		const dso = primaryHolding.dso;
		const factoryCid = normalizeContractId(externalAmuletRulesDisclosure.contractId || externalAmuletRulesDisclosure.contract_id);
		const amuletRulesCid = normalizeContractId(amuletRulesDisclosure.contractId || amuletRulesDisclosure.contract_id);
		const openRoundCid = normalizeContractId(openMiningRoundDisclosure.contractId || openMiningRoundDisclosure.contract_id);

		transferFactoryData = {
			factoryId: factoryCid,
			choiceContext: {
				choiceContextData: {
					values: {
						"open-round": { tag: "AV_ContractId", value: openRoundCid },
						"amulet-rules": { tag: "AV_ContractId", value: amuletRulesCid },
					},
				},
				disclosedContracts: [
					{
						templateId: externalAmuletRulesDisclosure.templateId || externalAmuletRulesDisclosure.template_id,
						contractId: factoryCid,
						createdEventBlob: externalAmuletRulesDisclosure.createdEventBlob || externalAmuletRulesDisclosure.created_event_blob,
						synchronizerId:
							externalAmuletRulesDisclosure.synchronizerId ||
							externalAmuletRulesDisclosure.synchronizer_id ||
							externalAmuletRulesDisclosure.domainId ||
							externalAmuletRulesDisclosure.domain_id,
					},
					{
						templateId: amuletRulesDisclosure.templateId || amuletRulesDisclosure.template_id,
						contractId: amuletRulesCid,
						createdEventBlob: amuletRulesDisclosure.createdEventBlob || amuletRulesDisclosure.created_event_blob,
						synchronizerId: amuletRulesDisclosure.synchronizerId || amuletRulesDisclosure.synchronizer_id || amuletRulesDisclosure.domainId || amuletRulesDisclosure.domain_id,
					},
					{
						templateId: openMiningRoundDisclosure.templateId || openMiningRoundDisclosure.template_id,
						contractId: openRoundCid,
						createdEventBlob: openMiningRoundDisclosure.createdEventBlob || openMiningRoundDisclosure.created_event_blob,
						synchronizerId:
							openMiningRoundDisclosure.synchronizerId || openMiningRoundDisclosure.synchronizer_id || openMiningRoundDisclosure.domainId || openMiningRoundDisclosure.domain_id,
					},
				],
			},
			transfer: {
				amount: totalQuantity,
				instrumentId: { admin: dso, id: "Amulet" },
			},
			expectedAdmin: dso,
		};
	} else {
		// Pass 0 as amount to let the factory calculate the total effective amount
		transferFactoryData = await getTransferFactory(party, primaryHolding.dso, 0, normalizedHoldingIds);
	}

	if (!transferFactoryData || !transferFactoryData.choiceContext) {
		console.error(`Failed to get transfer factory for merging holdings of party ${party}`);
		return null;
	}

	// Extract the factory contract ID and choice context
	const factoryContractId = normalizeContractId(transferFactoryData.factoryId);
	const choiceContextRaw = transferFactoryData.choiceContext.choiceContextData;
	const disclosedContractsRaw = transferFactoryData.choiceContext.disclosedContracts || [];
	const choiceContext = normalizeContractReferences(choiceContextRaw);
	const disclosedContracts = normalizeContractReferences(disclosedContractsRaw);

	// Get the actual transfer metadata from the factory response (accounts for holding fees)
	const transferInstruction = transferFactoryData.transfer || {};
	// Format amount to avoid floating point precision issues (Numeric 10 max precision)
	const rawAmount = transferInstruction.amount || totalQuantity;
	const actualAmount = parseFloat(parseFloat(rawAmount).toFixed(10));
	const instrumentAdmin = transferInstruction.instrumentId?.admin || primaryHolding.dso;
	const instrumentIdValue = transferInstruction.instrumentId?.id || "Amulet";
	const expectedAdmin = transferFactoryData.expectedAdmin || instrumentAdmin;

	// Build the transfer command using the transfer factory
	const schema = getSchema("executeTransferFactory");
	const now = new Date();
	// requestedAt MUST be in the past for Canton transfers
	const requestedAt = new Date(now.getTime() - 60 * 1000); // 1 minute in the past
	// executeBefore should be well in the future to allow processing time
	const executeBefore = new Date(now.getTime() + 3600 * 1000); // 1 hour in the future

	const templateVars = {
		factory_contract_id: factoryContractId,
		expected_admin: expectedAdmin,
		instrument_admin: instrumentAdmin,
		instrument_id: instrumentIdValue,
		investor: party,
		amount: actualAmount.toString(),
		holding_ids: normalizedHoldingIds,
		time: requestedAt.toISOString(),
		timeEnd: executeBefore.toISOString(),
		choice_context: choiceContext,
		disclosed_contracts: disclosedContracts,
		user_id: config.AUTH0_USER_ID || party,
		randomUUID: randomUUID(),
	};

	const command = replaceTemplateVariables(schema, templateVars);

	if (returnCommand) {
		return { command, endpoint: `${config.VALIDATOR_API_URL}/v2/commands/submit-and-wait` };
	}

	const headers = await buildHeaders();
	const endpoint = `${config.VALIDATOR_API_URL}/v2/commands/submit-and-wait`;

	try {
		const response = await axios.post(endpoint, command, { headers });
		// Merge successful
		return response.data;
	} catch (error) {
		console.error(`Error executing transfer factory for merge: ${error}`);
		if (error.response) {
			console.error(`Response data: ${JSON.stringify(error.response.data)}`);
		}
		return null;
	}
}

/**
 * Merge all utility token holdings of a specific asset for a party into a single holding.
 * Requires at least 2 holdings to merge.
 * @param {string} party - The party ID
 * @param {string} utilityAsset - The utility asset ID (e.g., "USDCx", "CBTC")
 * @param {boolean} [returnCommand=false] - If true, returns the raw command/endpoint instead of executing. Forced to true when provider is set.
 * @param {Object} [provider=null] - Wallet provider (e.g., Loop Wallet) with getActiveContracts(). When set, skips ledger API calls and returns the command for the wallet to sign.
 * @param {number} [maxUtxos=null] - Maximum number of UTXOs to merge. When set, picks the smallest holdings first.
 * @returns {Promise<Object|null>} Merge result data, or {command, endpoint} when returnCommand is true, or null on failure
 */
export async function mergeUtilityHoldingsForParty(party, utilityAsset, returnCommand = false, provider = null, maxUtxos = null) {
	provider = resolveProvider(provider);
	if (provider) {
		returnCommand = true;
		// Wallet providers (e.g., Loop) have a ~100 contract limit per transaction.
		// Default to 100 when no explicit maxUtxos is set.
		if (!maxUtxos) {
			maxUtxos = 100;
		}
	}

	if (!provider) {
		const ledgerEnd = await getLedgerEnd();
		if (ledgerEnd === null) {
			console.error("Cannot retrieve ledger end. Aborting mergeUtilityHoldingsForParty.");
			return null;
		}
	}

	// To merge utility tokens we need to transfer them to the same party with a combined output of the total amount

	const holdings = await getUtilityHoldingsForParty(party, false, provider);
	if (!holdings || holdings.length < 2) {
		console.error(`Not enough holdings to merge for party ${party}`);
		return null;
	}

	// Extract the actual contract data and map to a simpler structure, filtering by utility asset
	const contracts = holdings
		.map((h) => {
			const createdEvent = h.contractEntry?.JsActiveContract?.createdEvent;
			if (!createdEvent) return null;
			const synchronizerId = h.contractEntry?.JsActiveContract?.synchronizerId;
			const createArg = createdEvent.createArgument;

			const source = createArg?.instrument?.source || null;
			const rawAmount = createArg?.amount || "0";
			const quantity = parseFloat(rawAmount);
			const asset = createArg?.instrument?.id || null;
			const lock = createArg?.lock || false;
			// Extract the holder from the holding contract (for utility tokens)
			// Try multiple possible field names
			const holder = createArg?.holder || createArg?.owner || createArg?.account?.owner || null;
			// Extract operator, provider, registrar from holding for group identifier
			const operator = createArg?.operator || null;
			const provider = createArg?.provider || null;
			const registrar = createArg?.registrar || null;

			if (lock || asset !== utilityAsset) {
				return null; // Skip locked holdings or different asset types
			}
			const contractId = normalizeContractId(createdEvent.contractId);
			return {
				contractId,
				templateId: createdEvent.templateId,
				quantity: quantity,
				rawAmount: rawAmount,
				createdEventBlob: createdEvent.createdEventBlob,
				synchronizerId: synchronizerId,
				source: source,
				asset: asset,
				holder: holder,
				operator: operator,
				provider: provider,
				registrar: registrar,
			};
		})
		.filter((c) => c !== null && c.asset === utilityAsset);

	if (contracts.length < 2) {
		console.error(`Not enough valid ${utilityAsset} holdings to merge for party ${party}. Found ${contracts.length} holdings.`);
		return null;
	}

	// Filter holdings to ensure they all have the same operator/provider group
	// The AllocationFactory expects all inputs to belong to the same group identifier
	const uniqueOperators = [...new Set(contracts.map((c) => c.operator).filter(Boolean))];
	const uniqueProviders = [...new Set(contracts.map((c) => c.provider).filter(Boolean))];

	// If we have holdings with different operators/providers, filter to the most common group
	if (uniqueOperators.length > 1 || uniqueProviders.length > 1) {
		console.warn(`Found holdings with mixed operator/provider groups. Filtering to match Temple operator...`);
		// Count holdings per operator to find the dominant group
		const operatorCounts = {};
		contracts.forEach((c) => {
			const op = c.operator || "unknown";
			operatorCounts[op] = (operatorCounts[op] || 0) + 1;
		});
		// Prefer Temple operator, or fall back to most common
		const templeOperator = Object.keys(operatorCounts).find((op) => op.startsWith("Temple::"));
		const targetOperator = templeOperator || Object.keys(operatorCounts).sort((a, b) => operatorCounts[b] - operatorCounts[a])[0];

		// Filter to only holdings with the target operator
		const filteredContracts = contracts.filter((c) => c.operator === targetOperator);
		// Filtered holdings to match target operator

		if (filteredContracts.length < 2) {
			console.error(`Not enough holdings with matching operator after filtering. Found ${filteredContracts.length} holdings.`);
			return null;
		}

		// Replace contracts with filtered list
		contracts.length = 0;
		contracts.push(...filteredContracts);
	}

	// Filter by holder/owner - only merge holdings belonging to the same party
	// The requesting party parameter should match the holder field in holdings
	const uniqueHolders = [...new Set(contracts.map((c) => c.holder).filter(Boolean))];
	if (uniqueHolders.length > 1) {
		console.warn(`Found holdings for multiple holders (${uniqueHolders.join(", ")}). Filtering to match requesting party...`);

		// Try to find holdings that match the requesting party
		let targetHolder = uniqueHolders.find((h) => h === party || h.startsWith(party.split("::")[0] + "::"));

		if (!targetHolder) {
			// If no exact match, prefer the first holder (most holdings)
			const holderCounts = {};
			contracts.forEach((c) => {
				const h = c.holder || "unknown";
				holderCounts[h] = (holderCounts[h] || 0) + 1;
			});
			targetHolder = Object.keys(holderCounts).sort((a, b) => holderCounts[b] - holderCounts[a])[0];
		}

		const filteredByHolder = contracts.filter((c) => c.holder === targetHolder);

		if (filteredByHolder.length < 2) {
			console.error(`Not enough holdings with matching holder after filtering. Found ${filteredByHolder.length} holdings.`);
			return null;
		}

		// Replace contracts with filtered list
		contracts.length = 0;
		contracts.push(...filteredByHolder);
	}

	// Recalculate unique holders after filtering
	const finalHolders = [...new Set(contracts.map((c) => c.holder).filter(Boolean))];
	const holder = finalHolders[0] || party; // Use the holder from filtered holdings

	// Sort ascending by quantity so smallest UTXOs are merged first
	if (maxUtxos) {
		contracts.sort((a, b) => a.quantity - b.quantity);
		if (contracts.length > maxUtxos) {
			contracts.length = maxUtxos;
		}
		if (contracts.length < 2) {
			console.error(`Not enough holdings after applying maxUtxos limit (${maxUtxos}). Found ${contracts.length}.`);
			return null;
		}
	}

	// Calculate total quantity using precise decimal math (BigInt) to avoid floating point drift
	const totalQuantity = sumDecimalStrings(contracts.map((c) => c.rawAmount));

	// Gather holding contract IDs to merge
	const holdingIds = contracts.map((c) => c.contractId);
	const normalizedHoldingIds = normalizeContractReferences(holdingIds);

	const uniqueSources = [...new Set(contracts.map((c) => c.source).filter(Boolean))];
	if (uniqueSources.length === 0) {
		console.error(`Unable to resolve registrar for ${utilityAsset} holdings; merger aborted.`);
		return null;
	}
	if (uniqueSources.length > 1) {
		console.error(`Found holdings for multiple registrars (${uniqueSources.join(", ")}); merge requires a single registrar context.`);
		return null;
	}

	const registrar = uniqueSources[0];

	// Resolve transfer factory:
	// - Localhost: build from local ledger contracts (handles both Amulet and utility)
	// - Remote: use the instrument's Registry API (Scan API only handles Amulet)
	let transferFactoryData;
	if (shouldUseLedgerForMetadata()) {
		transferFactoryData = await getTransferFactory(holder, registrar, totalQuantity, normalizedHoldingIds, false, utilityAsset);
	} else {
		transferFactoryData = await getTransferFactoryFromRegistry(holder, registrar, totalQuantity, normalizedHoldingIds, utilityAsset);
	}
	if (!transferFactoryData || !transferFactoryData.choiceContext) {
		console.error(`Failed to retrieve transfer factory context for ${utilityAsset} holdings of party ${party}`);
		return null;
	}

	const factoryContractId = normalizeContractId(transferFactoryData.factoryId);
	if (!factoryContractId) {
		console.error(`Transfer factory response missing factoryId for ${utilityAsset} holdings.`);
		return null;
	}

	const transferInstruction = transferFactoryData.transfer || {};
	// Use factory amount if available, fall back to our precise sum
	const rawAmount = transferInstruction.amount || totalQuantity;
	const actualAmount = parseFloat(parseFloat(rawAmount).toFixed(10));
	const instrumentAdmin = transferInstruction.instrumentId?.admin || registrar;
	const instrumentIdValue = transferInstruction.instrumentId?.id || utilityAsset;
	// For utility tokens the TransferFactory is registrar-administered, so expectedAdmin = registrar.
	// Prefer the value returned by the Registry API, then fall back to the registrar from holdings.
	const expectedAdmin = transferFactoryData.expectedAdmin || registrar;

	const choiceContextRaw = transferFactoryData.choiceContext.choiceContextData || {};
	const disclosedContractsRaw = transferFactoryData.choiceContext.disclosedContracts || [];
	const choiceContext = normalizeContractReferences(choiceContextRaw);
	let disclosedContracts = normalizeContractReferences(disclosedContractsRaw);

	// Add input holdings as disclosed contracts - required for AllocationFactory to verify group identifiers
	// The holdings need to be disclosed for the factory to see their content
	const holdingDisclosures = contracts
		.filter((c) => c.createdEventBlob && c.contractId)
		.map((c) => ({
			templateId: c.templateId || `${config.PACKAGE_UTILITY_APP_ID}:Utility.Registry.Holding.V0.Holding:Holding`,
			contractId: normalizeContractId(c.contractId),
			createdEventBlob: c.createdEventBlob,
			synchronizerId: c.synchronizerId || config.GLOBAL_SYNCHRONIZER_ID,
		}));

	if (holdingDisclosures.length > 0) {
		// Add holding disclosures to transfer command
		disclosedContracts = [...disclosedContracts, ...holdingDisclosures];
	}

	const now = new Date();
	// requestedAt MUST be in the past for Canton transfers
	const requestedAt = new Date(now.getTime() - 60 * 1000); // 1 minute in the past
	// executeBefore should be well in the future to allow processing time
	const executeBefore = new Date(now.getTime() + 3600 * 1000); // 1 hour in the future

	const schema = getSchema("executeTransferFactory");
	const templateVars = {
		factory_contract_id: factoryContractId,
		expected_admin: expectedAdmin,
		instrument_admin: instrumentAdmin,
		instrument_id: instrumentIdValue,
		investor: holder, // Use holder from holdings, not the query party
		amount: actualAmount.toString(),
		holding_ids: normalizedHoldingIds,
		time: requestedAt.toISOString(),
		timeEnd: executeBefore.toISOString(),
		choice_context: choiceContext,
		disclosed_contracts: disclosedContracts,
		user_id: config.AUTH0_USER_ID || party,
		randomUUID: randomUUID(),
	};

	const command = replaceTemplateVariables(schema, templateVars);

	if (returnCommand) {
		return { command, endpoint: `${config.VALIDATOR_API_URL}/v2/commands/submit-and-wait` };
	}

	const headers = await buildHeaders();
	const endpoint = `${config.VALIDATOR_API_URL}/v2/commands/submit-and-wait`;

	try {
		const response = await axios.post(endpoint, command, { headers });
		// Utility merge successful
		return response.data;
	} catch (error) {
		console.error(`Error executing transfer factory for ${utilityAsset} merge: ${error}`);
		if (error.response) {
			console.error(`Response data: ${JSON.stringify(error.response.data)}`);
		}
		return null;
	}
}

/**
 * Split an Amulet holding into multiple holdings with specified output quantities.
 * @param {string} party - The party ID
 * @param {number[]} outputQuantity - Array of desired output quantities
 * @param {boolean} [returnCommand=false] - If true, returns the raw command/endpoint instead of executing
 * @returns {Promise<Object|null>} Split result data, or null on failure
 */
export async function splitAmuletHoldingForParty(party, outputQuantity, returnCommand = false) {
	// Splitting amulets is similar to merging but in reverse
	// We transfer from one holding into multiple holdings with specified output quantities

	const holding = await getCandidateHoldingForOrderCreation(party, true, outputQuantity);
	if (!holding || holding.error) {
		console.error(`No suitable holding found for party ${party} to split.`);
		return null;
	}

	// Get the transfer factory for the split
	const holdingIds = [holding.contractId];
	const normalizedHoldingIds = normalizeContractReferences(holdingIds);
	// Pass 0 as amount to let the factory calculate the total effective amount
	const transferFactoryData = await getTransferFactory(party, holding.dso, 0, normalizedHoldingIds);
	if (!transferFactoryData || !transferFactoryData.choiceContext) {
		console.error(`Failed to get transfer factory for splitting holding of party ${party}`);
		return null;
	}

	// Extract the factory contract ID and choice context
	const factoryContractId = normalizeContractId(transferFactoryData.factoryId);
	const choiceContextRaw = transferFactoryData.choiceContext.choiceContextData;
	const disclosedContractsRaw = transferFactoryData.choiceContext.disclosedContracts || [];
	const choiceContext = normalizeContractReferences(choiceContextRaw);
	const disclosedContracts = normalizeContractReferences(disclosedContractsRaw);

	// Get the actual transfer amount from the factory response (accounts for holding fees)
	const transferInstruction = transferFactoryData.transfer || {};
	const actualAmount = transferInstruction.amount || outputQuantity;
	const instrumentAdmin = transferInstruction.instrumentId?.admin || holding.dso;
	const instrumentIdValue = transferInstruction.instrumentId?.id || "Amulet";
	const expectedAdmin = transferInstruction.instrumentId?.admin || transferFactoryData.expectedAdmin || holding.dso;

	// Build the transfer command using the transfer factory
	const schema = getSchema("executeTransferFactory");
	const now = new Date();
	// Setting executeBefore to 30 seconds from now to account for processing time
	const executeBefore = new Date(now.getTime() + 30 * 1000);

	const templateVars = {
		factory_contract_id: factoryContractId,
		expected_admin: expectedAdmin,
		instrument_admin: instrumentAdmin,
		instrument_id: instrumentIdValue,
		investor: party,
		amount: actualAmount.toString(),
		holding_ids: normalizedHoldingIds,
		time: now.toISOString(),
		timeEnd: executeBefore.toISOString(),
		choice_context: choiceContext,
		disclosed_contracts: disclosedContracts,
		user_id: config.AUTH0_USER_ID,
		randomUUID: randomUUID(),
	};

	const command = replaceTemplateVariables(schema, templateVars);

	if (returnCommand) {
		return { command, endpoint: `${config.VALIDATOR_API_URL}/v2/commands/submit-and-wait` };
	}

	const headers = await buildHeaders();
	const endpoint = `${config.VALIDATOR_API_URL}/v2/commands/submit-and-wait`;

	try {
		const response = await axios.post(endpoint, command, { headers });
		// Split successful
		return response.data;
	} catch (error) {
		console.error(`Error executing transfer factory for split: ${error}`);
		if (error.response) {
			console.error(`Response data: ${JSON.stringify(error.response.data)}`);
		}
		return null;
	}
}

/**
 * Unlock all locked Amulet holdings for a party.
 * @param {string} party - The party ID
 * @param {boolean} [returnCommand=false] - If true, returns the raw commands instead of executing
 * @returns {Promise<Array|null>} Array of unlock results, or null if no locked amulets found
 */
export async function unlockLockedAmulets(party, returnCommand = false) {
	const lockedHoldings = await getLockedAmuletHoldingsForParty(party);
	if (!lockedHoldings || lockedHoldings.length === 0) {
		// No locked amulets found
		return null;
	}

	// Process locked amulets

	// Get the amulet rules first
	const amuletRulesData = await getAmuletRules(config.VALIDATOR_DSO_PARTY_ID);
	if (!amuletRulesData || !amuletRulesData.amulet_rules || Object.keys(amuletRulesData.amulet_rules).length === 0) {
		console.error(`No Amulet Transfer Rules found for DSO ${config.VALIDATOR_DSO_PARTY_ID}`);
		return null;
	}

	// Get a candidate mining round
	const miningRound = await getCandidateMiningRoundContract(config.VALIDATOR_DSO_PARTY_ID);
	if (!miningRound) {
		console.error(`No open Mining Round found for DSO ${config.VALIDATOR_DSO_PARTY_ID}`);
		return null;
	}

	const featuredAppRightMetadata = await resolveFeaturedAppRightMetadata();
	if (!featuredAppRightMetadata) {
		console.error("Unable to resolve Featured App Right metadata required for unlocking amulets.");
		return null;
	}

	const results = [];
	const endpoint = `${config.VALIDATOR_API_URL}/v2/commands/submit-and-wait`;

	// Unlock each locked amulet
	for (const holdingData of lockedHoldings) {
		const createdEvent = holdingData.contractEntry?.JsActiveContract?.createdEvent;
		if (!createdEvent) {
			console.warn(`Skipping invalid locked amulet holding data`);
			continue;
		}

		const lockedAmuletCid = createdEvent.contractId;
		const lockedAmuletTemplateId = createdEvent.templateId || null;
		const quantity = parseFloat(createdEvent.createArgument?.amount?.initialAmount || createdEvent.createArgument?.amulet?.amount?.initialAmount || 0);

		// Unlock this locked amulet

		// Build full template IDs using actual values from contracts, with env fallback
		const amuletRulesTemplateId = amuletRulesData.amulet_rules.contract.template_id || "#splice-amulet:Splice.AmuletRules:AmuletRules";
		const openMiningRoundTemplateId = miningRound.templateId || "#splice-amulet:Splice.Round:OpenMiningRound";
		// FeaturedAppRight template ID - NO FALLBACK, must come from env
		const featuredAppRightTemplateId = config.TEMPLATE_ID_FEATURED_APP;
		const lockedTemplateId = lockedAmuletTemplateId || "#splice-amulet:Splice.Amulet:LockedAmulet";

		const schema = getSchema("unlockAmulet");
		const templateVars = {
			locked_amulet_cid: lockedAmuletCid,
			locked_amulet_template_id: lockedTemplateId,
			open_mining_round_cid: miningRound.contractId,
			investor: party,
			user_id: config.AUTH0_USER_ID,
			randomUUID: randomUUID(),
			// Template IDs for disclosed contracts
			amulet_rules_template_id: amuletRulesTemplateId,
			open_mining_round_template_id: openMiningRoundTemplateId,
			featured_app_right_template_id: featuredAppRightTemplateId,
			// Amulet Rules disclosure
			transfer_rules_cid: amuletRulesData.amulet_rules.contract.contract_id,
			transfer_rules_disclosure: amuletRulesData.amulet_rules.contract.created_event_blob,
			transfer_rules_synchronizer: amuletRulesData.amulet_rules.domain_id,
			// Open Mining Round disclosure
			open_mining_round_disclosure: miningRound.createdEventBlob,
			open_mining_round_synchronizer: miningRound.synchronizerId,
			// Featured App Right disclosure
			featured_app_right_cid: featuredAppRightMetadata.contractCid,
			featured_app_right_disclosure: featuredAppRightMetadata.disclosureCid,
			featured_app_right_synchronizer: featuredAppRightMetadata.synchronizerId,
		};

		const command = replaceTemplateVariables(schema, templateVars);

		if (returnCommand) {
			results.push({ command, endpoint, contractId: lockedAmuletCid, amount: quantity });
			continue;
		}

		const headers = await buildHeaders();

		try {
			const response = await axios.post(endpoint, command, { headers });
			// Unlock successful
			results.push({ success: true, contractId: lockedAmuletCid, amount: quantity, data: response.data });
		} catch (error) {
			console.error(`Error unlocking amulet ${lockedAmuletCid}: ${error}`);
			if (error.response) {
				console.error(`Response data: ${JSON.stringify(error.response.data)}`);
			}
			results.push({ success: false, contractId: lockedAmuletCid, amount: quantity, error: error.message });
		}
	}

	if (returnCommand) {
		return results;
	}

	return results;
}

/**
 * Prepare holding contract IDs and formatted opts for depositFunds.
 * Selects the largest unlocked UTXOs until the requested amount is covered.
 *
 * @param {number|string} amount - The amount needed.
 * @param {string} symbol - Instrument symbol: "CC", "Amulet", "USDCx", "CBTC", etc.
 * @param {Object|null} [provider=null] - Optional wallet provider.
 * @returns {Promise<Object>} Object matching depositFunds opts shape, or { error }.
 */
export async function prepareDepositHoldings(amount, symbol) {
	const provider = resolveProvider(null);
	if (!provider && !config.VALIDATOR_SCAN_API_URL) {
		return { error: "prepareDepositHoldings: wallet provider is required to prepare holdings. Connect a wallet adapter." };
	}

	const party = getAdapterPartyId() ?? config.VALIDATOR_USER_PARTY_ID;
	if (!party) {
		return { error: "prepareDepositHoldings: party ID is required. Connect a wallet adapter or configure VALIDATOR_USER_PARTY_ID." };
	}

	// Normalize symbol: CC → Amulet
	let assetId = symbol?.trim();
	if (assetId === "CC") assetId = "Amulet";

	if (!instrumentCatalog[assetId]) {
		return { error: `prepareDepositHoldings: unsupported symbol "${symbol}"` };
	}

	const requiredAmount = parseFloat(amount);
	if (isNaN(requiredAmount) || requiredAmount <= 0) {
		return { error: "prepareDepositHoldings: amount must be a positive number" };
	}

	const isAmulet = assetId === "Amulet";
	const holdings = isAmulet ? await getAmuletHoldingsForParty(party, false, provider) : await getUtilityHoldingsForParty(party, false, provider);

	if (!holdings || holdings.length === 0) {
		return { error: `prepareDepositHoldings: no holdings found for party ${party}` };
	}

	// Parse holdings into { contractId, quantity } and filter out locked
	const parsed = [];
	for (const h of holdings) {
		const createdEvent = h.contractEntry?.JsActiveContract?.createdEvent;
		if (!createdEvent) continue;

		// Skip asset types that don't match the requested symbol
		const createdAssetId = createdEvent.createArgument?.instrument?.id || (isAmulet ? "Amulet" : null);
		if (createdAssetId !== assetId) continue;

		// Skip locked utility holdings
		if (!isAmulet && createdEvent.createArgument?.lock) continue;

		const quantity = isAmulet ? parseFloat(createdEvent.createArgument?.amount?.initialAmount || 0) : parseFloat(createdEvent.createArgument?.amount || 0);

		if (quantity <= 0) continue;

		parsed.push({
			contractId: normalizeContractId(createdEvent.contractId),
			quantity,
		});
	}

	if (parsed.length === 0) {
		return { error: `prepareDepositHoldings: no unlocked holdings found for ${assetId}` };
	}

	// Sort descending — largest first
	parsed.sort((a, b) => b.quantity - a.quantity);

	// Greedily select until we cover the required amount
	const selected = [];
	let cumulative = 0;
	for (const holding of parsed) {
		selected.push(holding.contractId);
		cumulative += holding.quantity;
		if (cumulative >= requiredAmount) break;
	}

	if (cumulative < requiredAmount) {
		return {
			error: `prepareDepositHoldings: insufficient balance. Have ${cumulative}, need ${requiredAmount}`,
			data: { totalBalance: cumulative, requiredAmount },
		};
	}

	const formattedAmount = parseFloat(parseFloat(amount).toFixed(10)).toString();

	return {
		sender: party,
		receiver: party,
		assetId,
		amount: formattedAmount,
		holdingCids: selected,
	};
}

/**
 * Create a CIP-56 Allocation.
 * Fetches the AllocationFactory, then exercises AllocationFactory_Allocate
 * to lock holdings for a settlement leg.
 *
 * For Amulet: uses the Scan API (VALIDATOR_SCAN_API_URL) with DSO as admin.
 * For utility tokens: uses the Registry API from the instrument catalog with registrar as admin.
 *
 * Flow:
 *   1. Resolve admin and factory URL (Scan API for Amulet, Registry API for utility).
 *   2. POST .../allocation-instruction/v1/allocation-factory to get
 *      factoryId, choiceContextData, and disclosedContracts.
 *   3. Build an ExerciseCommand on the AllocationFactory interface with the
 *      AllocationFactory_Allocate choice.
 *   4. Submit via the Ledger API submit-and-wait endpoint.
 *
 * @param {Object} opts
 * @param {string} opts.sender       - The party allocating the assets.
 * @param {string} opts.receiver     - The counterparty receiving in the settlement leg.
 * @param {string} opts.assetId      - Instrument symbol (e.g. "USDCx", "Amulet").
 * @param {string|number} opts.amount - Amount to allocate.
 * @param {string[]} opts.holdingCids - Holding contract IDs that fund the allocation.
 * @param {string} opts.settlementId - A reference id for the settlement.
 * @param {string} opts.transferLegId - Unique id for this transfer leg.
 * @param {string} [opts.allocateBefore] - ISO timestamp; deadline for allocation (default: +1 h).
 * @param {string} [opts.settleBefore]   - ISO timestamp; deadline for settlement (default: +2 h).
 * @param {Object} [opts.disclosures]    - Pre-fetched Amulet disclosures (from /api/amulet/disclosures). Required for Amulet when no Scan API or ledger access.
 * @param {string} [opts.userId]         - Temple user ID. Falls back to wallet adapter → AUTH0_USER_ID → "temple".
 * @param {boolean} [returnCommand=false] - If true, returns { command, endpoint } instead of executing.
 * @returns {Promise<Object|null>} Ledger API response (or { error } on failure).
 */
export async function depositFunds(opts, returnCommand = false) {
	const { sender, receiver, assetId, amount, holdingCids = [], settlementId, transferLegId, allocateBefore, settleBefore, disclosures, userId } = opts;

	if (!sender || !assetId || !amount) {
		const msg = "depositFunds: sender, assetId, and amount are required";
		console.error(msg);
		return { error: msg };
	}

	const isAmulet = assetId === "Amulet";

	// --- 1. Resolve admin and factory ---
	// Amulet: admin = DSO, factory from Scan API (or ledger on localhost)
	// Utility: admin = registrar from instrument catalog, factory from Registry API (or ledger on localhost)
	let admin;
	let factoryContractId;
	let choiceContextData = {};
	let disclosedContracts = [];

	if (isAmulet) {
		admin = config.VALIDATOR_DSO_PARTY_ID;
	} else {
		const instrumentDef = resolveInstrumentDefinition(assetId);
		const networkContracts = instrumentDef?.[config.NETWORK];
		admin = networkContracts?.registrar || getInstrumentRegistrar(assetId) || config.VALIDATOR_REGISTRAR_PARTY_ID;
	}

	// --- 2. Build the choice arguments upfront ---
	// Needed both for the factory request (Registry API requires the full args) and the exercise command
	const now = new Date();
	const allocateDeadline = allocateBefore || new Date(now.getTime() + 60 * 60 * 1000).toISOString();
	const settleDeadline = settleBefore || new Date(now.getTime() + 2 * 60 * 60 * 1000).toISOString();
	const executor = config.TEMPLE_PARTY_ID;
	const resolvedTransferLegId = transferLegId || randomUUID();
	const resolvedSettlementId = settlementId || `SR-${randomUUID()}`;

	const choiceArgument = {
		expectedAdmin: admin,
		allocation: {
			settlement: {
				executor: executor,
				settlementRef: {
					id: resolvedSettlementId,
					cid: null,
				},
				requestedAt: now.toISOString(),
				allocateBefore: allocateDeadline,
				settleBefore: settleDeadline,
				meta: { values: config.ALLOCATION_META_TAG ? { tag: config.ALLOCATION_META_TAG } : {} },
			},
			transferLegId: resolvedTransferLegId,
			transferLeg: {
				sender: sender,
				receiver: receiver || sender,
				amount: parseFloat(parseFloat(amount).toFixed(10)).toString(),
				instrumentId: {
					admin: admin,
					id: assetId,
				},
				meta: { values: {} },
			},
		},
		requestedAt: now.toISOString(),
		inputHoldingCids: holdingCids.map(normalizeContractId),
		extraArgs: {
			context: { values: {} },
			meta: { values: {} },
		},
	};

	// --- 3. Fetch AllocationFactory ---
	if (shouldUseLedgerForMetadata()) {
		// Localhost: resolve factory and context from ledger directly
		if (isAmulet) {
			const amuletCtx = await resolveAmuletContext({ investor: sender, holdingIds: holdingCids, transferAmount: Number(amount) });
			if (!amuletCtx) {
				const msg = "depositFunds: failed to resolve Amulet context from ledger";
				console.error(msg);
				return { error: msg };
			}
			// ExternalPartyAmuletRules is the AllocationFactory for Amulet
			factoryContractId = normalizeContractId(amuletCtx.externalAmuletRules.contractCid);
			choiceContextData = {
				values: {
					[amuletCtx.contextKeys.amuletRules]: { tag: "AV_ContractId", value: amuletCtx.amuletRules.contractCid },
					[amuletCtx.contextKeys.openRound]: { tag: "AV_ContractId", value: amuletCtx.openMiningRound.contractCid },
					[amuletCtx.contextKeys.featuredAppRight]: { tag: "AV_ContractId", value: amuletCtx.featuredAppRight.contractCid },
				},
			};
			disclosedContracts = [
				{
					templateId: amuletCtx.amuletRules.templateId,
					contractId: amuletCtx.amuletRules.contractCid,
					createdEventBlob: amuletCtx.amuletRules.disclosureCid,
					synchronizerId: amuletCtx.amuletRules.synchronizerId,
				},
				{
					templateId: amuletCtx.openMiningRound.templateId,
					contractId: amuletCtx.openMiningRound.contractCid,
					createdEventBlob: amuletCtx.openMiningRound.disclosureCid,
					synchronizerId: amuletCtx.openMiningRound.synchronizerId,
				},
				{
					templateId: amuletCtx.externalAmuletRules.templateId,
					contractId: amuletCtx.externalAmuletRules.contractCid,
					createdEventBlob: amuletCtx.externalAmuletRules.disclosureCid,
					synchronizerId: amuletCtx.externalAmuletRules.synchronizerId,
				},
			];
			if (amuletCtx.featuredAppRight?.contractCid && amuletCtx.featuredAppRight?.disclosureCid) {
				disclosedContracts.push({
					templateId: amuletCtx.featuredAppRight.templateId,
					contractId: amuletCtx.featuredAppRight.contractCid,
					createdEventBlob: amuletCtx.featuredAppRight.disclosureCid,
					synchronizerId: amuletCtx.featuredAppRight.synchronizerId,
				});
			}
		} else {
			// Utility token: resolve from ledger
			const instrumentDef = resolveInstrumentDefinition(assetId);
			const registrar = instrumentDef?.[config.NETWORK]?.registrar || getInstrumentRegistrar(assetId) || config.VALIDATOR_REGISTRAR_PARTY_ID;
			const [allocFactory, instConfig] = await Promise.all([resolveUtilityAllocationFactory(registrar, sender), resolveUtilityInstrumentConfiguration(assetId, registrar)]);
			if (!allocFactory) {
				const msg = `depositFunds: no AllocationFactory found on ledger for ${assetId}`;
				console.error(msg);
				return { error: msg };
			}
			factoryContractId = normalizeContractId(allocFactory.contractCid);
			if (instConfig) {
				choiceContextData = {
					values: {
						[DEFAULT_UTILITY_CONTEXT_KEYS.instrumentConfiguration]: { tag: "AV_ContractId", value: instConfig.contractCid },
						[DEFAULT_UTILITY_CONTEXT_KEYS.instrumentConfigurationPrefixed]: { tag: "AV_ContractId", value: instConfig.contractCid },
						[DEFAULT_UTILITY_CONTEXT_KEYS.senderCredentials]: { tag: "AV_List", value: [] },
						[DEFAULT_UTILITY_CONTEXT_KEYS.senderCredentialsPrefixed]: { tag: "AV_List", value: [] },
						[DEFAULT_UTILITY_CONTEXT_KEYS.receiverCredentials]: { tag: "AV_List", value: [] },
						[DEFAULT_UTILITY_CONTEXT_KEYS.receiverCredentialsPrefixed]: { tag: "AV_List", value: [] },
					},
				};
				disclosedContracts.push({ templateId: null, contractId: instConfig.contractCid, createdEventBlob: instConfig.disclosureCid, synchronizerId: instConfig.synchronizerId });
			}
			disclosedContracts.push({ templateId: null, contractId: allocFactory.contractCid, createdEventBlob: allocFactory.disclosureCid, synchronizerId: allocFactory.synchronizerId });
		}
	} else if (isAmulet && !config.VALIDATOR_SCAN_API_URL) {
		// Amulet via disclosures (FE/proxy path — no API access)
		// Use pre-fetched disclosures if provided, otherwise fetch from API
		const factoryData = disclosures?.disclosures || disclosures || null;
		let resolvedFactoryData = factoryData;

		if (!resolvedFactoryData?.factoryId) {
			const disclosuresResult = await getDisclosures(sender);
			resolvedFactoryData = disclosuresResult?.disclosures;
			if (disclosuresResult?.error || !resolvedFactoryData?.factoryId) {
				const detail = disclosuresResult?.message || disclosuresResult?.error || "missing factoryId in response";
				const msg = `depositFunds: failed to resolve Amulet disclosures. Pass disclosures directly or ensure API access: ${detail}`;
				console.error(msg);
				return { error: msg };
			}
		}

		factoryContractId = normalizeContractId(resolvedFactoryData.factoryId);
		choiceContextData = resolvedFactoryData.choiceContext?.choiceContextData || {};
		disclosedContracts = (resolvedFactoryData.choiceContext?.disclosedContracts || []).map((dc) => ({
			templateId: dc.templateId,
			contractId: dc.contractId,
			createdEventBlob: dc.createdEventBlob,
			synchronizerId: dc.synchronizerId,
		}));
	} else {
		// Remote: use Scan API (Amulet) or Registry API (utility)
		let factoryUrl;
		let factoryHeaders = {};

		if (isAmulet) {
			factoryUrl = `${config.VALIDATOR_SCAN_API_URL}/registry/allocation-instruction/v1/allocation-factory`;
			factoryHeaders = await buildHeaders();
		} else {
			const instrumentDef = resolveInstrumentDefinition(assetId);
			const networkContracts = instrumentDef?.[config.NETWORK];
			const registryAPI = networkContracts?.registryAPI;

			if (!registryAPI) {
				const msg = `depositFunds: no registryAPI defined for ${assetId} on ${config.NETWORK}`;
				console.error(msg);
				return { error: msg };
			}
			factoryUrl = `${registryAPI}/allocation-instruction/v1/allocation-factory`;
		}

		const factoryBody = {
			choiceArguments: isAmulet ? {} : choiceArgument,
			excludeDebugFields: true,
		};
		let factoryData;
		try {
			const factoryResponse = await axios.post(factoryUrl, factoryBody, Object.keys(factoryHeaders).length > 0 ? { headers: factoryHeaders } : undefined);
			factoryData = factoryResponse.data;
		} catch (error) {
			const detail = error.response?.data ? JSON.stringify(error.response.data) : error.message;
			const msg = `depositFunds: error fetching allocation factory from ${isAmulet ? "Scan API" : "Registry API"}: ${detail}`;
			console.error(msg);
			return { error: msg };
		}

		factoryContractId = normalizeContractId(factoryData?.factoryId);
		choiceContextData = factoryData?.choiceContext?.choiceContextData || {};
		disclosedContracts = (factoryData?.choiceContext?.disclosedContracts || []).map((dc) => ({
			templateId: dc.templateId,
			contractId: dc.contractId,
			createdEventBlob: dc.createdEventBlob,
			synchronizerId: dc.synchronizerId,
		}));
	}

	if (!factoryContractId) {
		const msg = "depositFunds: allocation factory response missing factoryId";
		console.error(msg);
		return { error: msg };
	}

	// --- 4. Build the ExerciseCommand for AllocationFactory_Allocate ---
	// Merge the resolved choiceContextData into the extraArgs
	choiceArgument.extraArgs.context = choiceContextData;

	const command = {
		commands: [
			{
				ExerciseCommand: {
					templateId: "#splice-api-token-allocation-instruction-v1:Splice.Api.Token.AllocationInstructionV1:AllocationFactory",
					contractId: factoryContractId,
					choice: "AllocationFactory_Allocate",
					choiceArgument: choiceArgument,
				},
			},
		],
		commandId: randomUUID(),
		userId: userId || getUserId() || config.AUTH0_USER_ID || "temple",
		applicationId: "temple",
		actAs: [sender],
		disclosedContracts: disclosedContracts,
	};

	dedupeDisclosedContracts(command);
	const endpoint = `${config.VALIDATOR_API_URL}/v2/commands/submit-and-wait`;

	if (returnCommand) {
		return { command, endpoint };
	}

	// Auto-submit via wallet adapter if available
	if (getWalletAdapter()) {
		try {
			return await submitCommand(command);
		} catch (error) {
			const msg = `depositFunds: wallet adapter submission failed: ${error.message}`;
			console.error(msg);
			return { error: msg };
		}
	}

	const headers = await buildHeaders();
	try {
		const response = await axios.post(endpoint, command, { headers });
		return response.data;
	} catch (error) {
		const errorData = error?.response?.data;
		const errorDetail = errorData ? JSON.stringify(errorData, null, 2) : error.message;
		const msg = `depositFunds: error submitting command: ${errorDetail}`;
		console.error(msg);
		return { error: msg };
	}
}

// Withdrawal functions moved to src/canton/withdrawals.ts
export { finalizeWithdrawFunds, withdrawFunds, withdrawDelegation } from "../../dist/canton/withdrawals.js";

// ─── Onboarding & Delegation ─────────────────────────────────────────────────

/**
 * Create an OnboardingRequest contract on the ledger.
 *
 * The user creates this contract to request delegation to the operator.
 * The operator then exercises AcceptOnboarding to produce a Delegation contract.
 *
 * Template: Temple.Settlement.Onboarding:OnboardingRequest
 *
 * @param {object} user     - User info: { partyId, userId }. partyId is the Daml party; userId is for command submission (e.g. Auth0 sub).
 * @param {string} user.partyId - The Daml party representing the user (controller of the onboarding request).
 * @param {string} user.userId  - The user ID for command submission (e.g. Auth0 sub). Defaults to config.AUTH0_USER_ID or "temple".
 * @param {boolean} [returnCommand=false] - If true, returns { command, endpoint } without submitting.
 * @returns {Promise<Object>} Ledger API response, or { error } on failure.
 */
export async function onboardUser(user = {}, returnCommand = false) {
	user.partyId = user.partyId ?? getAdapterPartyId() ?? config.VALIDATOR_USER_PARTY_ID;
	user.userId = user.userId ?? getUserId() ?? config.AUTH0_USER_ID ?? "temple";
	if (!user.partyId) {
		const msg = "onboardUser: user party is required. Pass it directly, set WALLET_ADAPTER, or configure VALIDATOR_USER_PARTY_ID.";
		console.error(msg);
		return { error: msg };
	}

	const operator = config.TEMPLE_PARTY_ID;
	if (!operator) {
		const msg = "onboardUser: TEMPLE_PARTY_ID (operator) is not configured";
		console.error(msg);
		return { error: msg };
	}

	const command = {
		commands: [
			{
				CreateCommand: {
					templateId: `${config.PACKAGE_NAME_SETTLEMENT_IMPL}:Temple.Settlement.Onboarding:OnboardingRequest`,
					createArguments: {
						user: user.partyId,
						operator: operator,
					},
				},
			},
		],
		commandId: randomUUID(),
		userId: user.userId,
		applicationId: "temple",
		actAs: [user.partyId],
	};

	const endpoint = `${config.VALIDATOR_API_URL}/v2/commands/submit-and-wait`;

	if (returnCommand) {
		return { command, endpoint };
	}

	// Auto-submit via wallet adapter if available
	let submitResult;
	if (getWalletAdapter()) {
		try {
			submitResult = await submitCommand(command);
		} catch (error) {
			const msg = `onboardUser: wallet adapter submission failed: ${error.message}`;
			console.error(msg);
			return { error: msg };
		}
	} else {
		const headers = await buildHeaders();
		try {
			const response = await axios.post(endpoint, command, { headers });
			submitResult = response.data;
		} catch (error) {
			const errorData = error?.response?.data;
			const errorDetail = errorData ? JSON.stringify(errorData, null, 2) : error.message;
			const msg = `onboardUser: error submitting command: ${errorDetail}`;
			console.error(msg);
			return { error: msg };
		}
	}

	// Poll isUserOnboarded every 5s for up to 60s
	const pollInterval = 5_000;
	const maxAttempts = 12;
	for (let attempt = 1; attempt <= maxAttempts; attempt++) {
		await new Promise((resolve) => setTimeout(resolve, pollInterval));
		const delegation = await isUserOnboarded(user.partyId);
		if (delegation && !delegation.error) {
			console.log(`onboardUser: onboarding confirmed after ${attempt * 5}s`);
			return { ...submitResult, delegation };
		}
		if (attempt < maxAttempts) {
			console.log(`onboardUser: waiting for onboarding confirmation (${attempt * 5}s)...`);
		}
	}

	console.warn("onboardUser: command submitted but onboarding not confirmed within 60s");
	return { ...submitResult, warning: "Onboarding request submitted but delegation not confirmed within 60s" };
}


/**
 * Check if a user is already onboarded (has an active Delegation contract with the operator).
 *
 * Queries active contracts for a Delegation template where the user is a signatory.
 * Returns the Delegation contract if found, or null if not onboarded.
 *
 * @param {string} user - The party to check.
 * @param {boolean} [returnCommand=false] - If true, returns { command, endpoint } without executing.
 * @returns {Promise<Object|null>} The Delegation contract data if onboarded, null if not, or { error } on failure.
 */
export async function isUserOnboarded(user = null, returnCommand = false) {
	// ── API path: use delegation endpoint when no custom validator ──
	if (!config.VALIDATOR_API_URL || getWalletAdapter()) {
		const result = await getDelegation();
		if (result?.error) return null;
		return result?.delegation || null;
	}

	// ── Custom validator path: query ledger for delegation contract ──
	if (!user) {
		const msg = "isUserOnboarded: user party is required";
		console.error(msg);
		return { error: msg };
	}

	const ledgerEnd = await getLedgerEnd();
	if (ledgerEnd === null) {
		const msg = "isUserOnboarded: cannot retrieve ledger end";
		console.error(msg);
		return { error: msg };
	}

	const templateId = `${config.PACKAGE_NAME_SETTLEMENT_IMPL}:Temple.Settlement.Delegation:Delegation`;

	const command = {
		verbose: true,
		activeAtOffset: ledgerEnd,
		filter: {
			filtersByParty: {
				[user]: {
					cumulative: [
						{
							identifierFilter: {
								TemplateFilter: {
									value: {
										templateId,
										includeCreatedEventBlob: false,
									},
								},
							},
						},
					],
				},
			},
		},
	};

	const endpoint = `${config.VALIDATOR_API_URL}/v2/state/active-contracts`;

	if (returnCommand) {
		return { command, endpoint };
	}

	const headers = await buildHeaders();
	try {
		const response = await axios.post(endpoint, command, { headers });
		const contracts = unwrapActiveContracts(response.data);

		// Filter to find delegation with our operator
		const operator = config.TEMPLE_PARTY_ID;
		const delegation = contracts.find((entry) => {
			const payload = entry?.contractEntry?.JsActiveContract?.createdEvent?.createArgument;
			return payload?.user === user && payload?.operator === operator;
		});

		return delegation || null;
	} catch (error) {
		const errorData = error?.response?.data;
		const errorDetail = errorData ? JSON.stringify(errorData, null, 2) : error.message;
		const msg = `isUserOnboarded: error querying active contracts: ${errorDetail}`;
		console.error(msg);
		return { error: msg };
	}
}

/**
 * Get all balances for a party, grouped by asset type.
 * Returns Amulet, locked Amulet, and utility token holdings with totals.
 * @param {string|null} [party=null] - The party ID. Optional if authenticated via REST API or wallet adapter is set.
 * @param {Object|null} [provider=null] - Optional wallet provider. Falls back to wallet adapter if set.
 * @returns {Promise<Object>} Balances grouped by registrar and asset, each with total_balance, holdings, etc.
 */
export async function getUserBalances(party = null, provider = null) {
	provider = resolveProvider(provider);
	if (!provider && !config.VALIDATOR_API_URL) {
		const msg = "getUserBalances: no provider or API URL configured. Set up a wallet adapter or configure VALIDATOR_API_URL.";
		console.error(msg);
		return { error: msg };
	}
	party = party ?? getAdapterPartyId() ?? config.VALIDATOR_USER_PARTY_ID;
	if (!party) {
		return { error: "Party ID is required. Pass it directly, connect a wallet adapter, or configure VALIDATOR_USER_PARTY_ID." };
	}
	// Get all supported instrument IDs from the catalog
	const supportedInstruments = new Set(Object.keys(instrumentCatalog));

	// ── Provider path: use getHolding() for all balances ──
	if (provider) {
		const holdings = await provider.getHolding();

		const balances = [];
		for (const h of holdings || []) {
			const instrumentId = h.instrument_id?.id;
			const symbol = h.symbol;

			// Only include instruments in our catalog
			const catalogKey = supportedInstruments.has(instrumentId) ? instrumentId : instrumentIdToSymbol[instrumentId] || null;
			if (!catalogKey) continue;

			const catalogEntry = instrumentCatalog[catalogKey];
			const unlocked = parseFloat(h.total_unlocked_coin || "0");
			const locked = parseFloat(h.total_locked_coin || "0");

			balances.push({
				asset: catalogKey,
				symbol: symbol,
				total_balance: unlocked + locked,
				available_balance: unlocked,
				locked_balance: locked,
				dso: catalogEntry?.kind === "amulet" ? h.instrument_id?.admin || null : null,
				registrar: h.instrument_id?.admin || null,
				operator: catalogEntry?.operator || null,
				provider: catalogEntry?.provider || null,
				merge_warning: (h.total_utxos || 0) > 1,
				holdings: [],
				locked_holdings: [],
				utilityContext: null,
			});
		}

		return balances;
	}

	// ── Custom validator path: query individual contract types from ledger ──
	const promises = [getAmuletHoldingsForParty(party, false, null), getLockedAmuletHoldingsForParty(party, false, null), getUtilityHoldingsForParty(party, false, null)];

	const [amuletHoldings, lockedAmuletHoldings, utilityHoldings] = await Promise.all(promises);

	// Structure: assetsByKey[registrar][asset] = { ... }
	const assetsByKey = {};

	// Helper to initialize asset entry
	const initAssetEntry = (key, asset, metadata = {}) => {
		if (!assetsByKey[key]) {
			assetsByKey[key] = {};
		}
		if (!assetsByKey[key][asset]) {
			assetsByKey[key][asset] = {
				available_balance: 0,
				locked_balance: 0,
				holdings: [],
				locked_holdings: [],
				registrar: metadata.registrar || null,
				dso: metadata.dso || null,
				operator: metadata.operator || null,
				provider: metadata.provider || null,
				utilityContext: null,
			};
		}
		return assetsByKey[key][asset];
	};

	// Process unlocked Amulet holdings
	for (const holdingData of amuletHoldings || []) {
		const createdEvent = holdingData.contractEntry?.JsActiveContract?.createdEvent;
		if (!createdEvent) continue;

		const quantity = parseFloat(createdEvent.createArgument?.amount?.initialAmount || createdEvent.createArgument?.amulet?.amount?.initialAmount || 0);
		const dso = createdEvent.createArgument?.dso || createdEvent.createArgument?.amulet?.dso || "Unknown DSO";
		const synchronizerId = holdingData.contractEntry?.JsActiveContract?.synchronizerId || null;
		const disclosure = createdEvent.createdEventBlob || null;

		const catalogEntry = instrumentCatalog["Amulet"];
		const key = dso; // For Amulet, use DSO as the key
		const entry = initAssetEntry(key, "Amulet", {
			registrar: catalogEntry?.registrar || dso,
			dso: dso,
			operator: catalogEntry?.operator || null,
			provider: catalogEntry?.provider || null,
		});

		entry.available_balance += quantity;
		entry.holdings.push({
			contractId: createdEvent.contractId,
			quantity: quantity,
			disclosure,
			synchronizer: synchronizerId,
			dso: dso,
		});
	}

	// Process locked Amulet holdings
	for (const holdingData of lockedAmuletHoldings || []) {
		const createdEvent = holdingData.contractEntry?.JsActiveContract?.createdEvent;
		if (!createdEvent) continue;

		const quantity = parseFloat(createdEvent.createArgument?.amulet?.amount?.initialAmount || 0);
		const dso = createdEvent.createArgument?.amulet?.dso || "Unknown DSO";
		const synchronizerId = holdingData.contractEntry?.JsActiveContract?.synchronizerId || null;
		const disclosure = createdEvent.createdEventBlob || null;
		const lockHolder = createdEvent.createArgument?.lock?.holders?.[0] || null;
		const lockExpiry = createdEvent.createArgument?.lock?.expiresAt || null;

		const catalogEntry = instrumentCatalog["Amulet"];
		const key = dso;
		const entry = initAssetEntry(key, "Amulet", {
			registrar: catalogEntry?.registrar || dso,
			dso: dso,
			operator: catalogEntry?.operator || null,
			provider: catalogEntry?.provider || null,
		});

		entry.locked_balance += quantity;
		entry.locked_holdings.push({
			contractId: createdEvent.contractId,
			quantity: quantity,
			disclosure,
			synchronizer: synchronizerId,
			dso: dso,
			lockHolder,
			lockExpiry,
		});
	}

	// Process utility holdings - check lock status to separate locked/unlocked
	for (const holdingData of utilityHoldings || []) {
		const createdEvent = holdingData.contractEntry?.JsActiveContract?.createdEvent;
		if (!createdEvent) continue;

		const quantity = parseFloat(createdEvent.createArgument?.amount || 0);
		let asset = createdEvent.createArgument?.instrument?.id || "Unknown Utility";
		// Resolve on-chain instrument ID to catalog symbol (e.g. UUID -> "SBC")
		asset = instrumentIdToSymbol[asset] || asset;
		// Normalize "Amulet" utility tokens to "tAmulet" to distinguish from native Amulet
		if (asset === "Amulet") {
			asset = "tAmulet";
		}

		// Only include supported instruments
		if (!supportedInstruments.has(asset)) continue;

		const registrar = createdEvent.createArgument?.instrument?.source || "Unknown Registrar";
		const synchronizerId = holdingData.contractEntry?.JsActiveContract?.synchronizerId || null;
		const disclosure = createdEvent.createdEventBlob || null;

		// Check if the holding is locked
		const lockData = createdEvent.createArgument?.lock || null;
		const isLocked = lockData !== null;
		const lockHolder = lockData?.holders?.[0] || null;
		const lockExpiry = lockData?.expiresAt || null;

		const catalogEntry = instrumentCatalog[asset];
		const key = registrar;
		const entry = initAssetEntry(key, asset, {
			registrar: catalogEntry?.registrar || registrar,
			dso: null, // Utility tokens don't have DSO
			operator: catalogEntry?.operator || null,
			provider: catalogEntry?.provider || null,
		});

		if (isLocked) {
			entry.locked_balance += quantity;
			entry.locked_holdings.push({
				contractId: createdEvent.contractId,
				quantity: quantity,
				disclosure,
				synchronizer: synchronizerId,
				registrar: registrar,
				lockHolder,
				lockExpiry,
			});
		} else {
			entry.available_balance += quantity;
			entry.holdings.push({
				contractId: createdEvent.contractId,
				quantity: quantity,
				disclosure,
				synchronizer: synchronizerId,
				registrar: registrar,
			});
		}
	}

	// Resolve utility contexts (requires ledger API access — provider path returns early above)
	const utilityContextPromises = new Map();
	for (const key of Object.keys(assetsByKey)) {
		for (const asset of Object.keys(assetsByKey[key])) {
			if (asset === "Amulet") {
				continue;
			}
			const assetEntry = assetsByKey[key][asset];
			if (assetEntry.utilityContext) {
				continue;
			}
			const registrar = assetEntry.registrar || key;
			const cacheKey = `${registrar || "*"}::${asset}`;
			if (!utilityContextPromises.has(cacheKey)) {
				utilityContextPromises.set(
					cacheKey,
					resolveUtilityCip56Context({
						party,
						registrar,
						utilityAsset: asset,
					}),
				);
			}
		}
	}

	// Await all utility context promises
	for (const [key, promise] of utilityContextPromises.entries()) {
		utilityContextPromises.set(key, await promise);
	}

	// Assign utility contexts
	for (const key of Object.keys(assetsByKey)) {
		for (const asset of Object.keys(assetsByKey[key])) {
			if (asset === "Amulet") {
				continue;
			}
			const assetEntry = assetsByKey[key][asset];
			if (assetEntry.utilityContext) {
				continue;
			}
			const registrar = assetEntry.registrar || key;
			const cacheKey = `${registrar || "*"}::${asset}`;
			assetEntry.utilityContext = utilityContextPromises.get(cacheKey) || null;
			if (!assetEntry.registrar && assetEntry.utilityContext?.registrar) {
				assetEntry.registrar = assetEntry.utilityContext.registrar;
			}
		}
	}

	// Build the final balances array
	const balances = [];
	for (const key in assetsByKey) {
		for (const asset in assetsByKey[key]) {
			const assetEntry = assetsByKey[key][asset];
			balances.push({
				asset: asset,
				total_balance: assetEntry.available_balance + assetEntry.locked_balance,
				available_balance: assetEntry.available_balance,
				locked_balance: assetEntry.locked_balance,
				dso: assetEntry.dso,
				registrar: assetEntry.registrar,
				operator: assetEntry.operator,
				provider: assetEntry.provider,
				merge_warning: assetEntry.holdings.length > 1,
				holdings: assetEntry.holdings,
				locked_holdings: assetEntry.locked_holdings,
				utilityContext: assetEntry.utilityContext,
			});
		}
	}

	return balances;
}
